const GEOGRAPHY_OCR_PRACTICE = {
  '1.1': {
    name: 'Landscape Systems',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two processes of weathering that affect limestone landscapes.', marks: 2, markScheme: '• Chemical weathering / carbonation (1)\n• Mechanical/physical weathering e.g. freeze-thaw (1)' },
      { q: 'State two features of erosion found in a river\'s upper course.', marks: 2, markScheme: '• V-shaped valley (1)\n• Interlocking spurs (1)' },
      { q: 'State three factors that influence the rate of coastal erosion.', marks: 3, markScheme: '• Rock type/geology (1)\n• Wave energy/fetch (1)\n• Presence or absence of coastal defences (1)' },
      { q: 'Define the term "sediment budget" in the context of a coastal system.', marks: 2, markScheme: '• The balance between sediment inputs and outputs (1)\n• Within a defined coastal area/sediment cell (1)' },
      { q: 'State two landforms produced by glacial deposition.', marks: 2, markScheme: '• Drumlin (1)\n• Terminal/lateral moraine (1)\n• Erratic (1) (any two)' },
      { q: 'Define the term "dynamic equilibrium" as applied to landscape systems.', marks: 3, markScheme: '• A state of balance within a system (1)\n• Where inputs and outputs are roughly equal (1)\n• The system adjusts to maintain this balance when changes occur (1)' },
      { q: 'State two types of mass movement found on coastlines.', marks: 2, markScheme: '• Rotational slumping (1)\n• Rockfall (1)\n• Landslide (1)\n• Mudflow (1) (any two)' },
      { q: 'State two characteristics of constructive waves.', marks: 2, markScheme: '• Low wave height / long wavelength (1)\n• Strong swash, weak backwash (1)\n• Low frequency (6-8 per minute) (1) (any two)' },
      { q: 'Define the term "abrasion" in the context of fluvial erosion.', marks: 2, markScheme: '• The wearing away of the river bed and banks (1)\n• By the river\'s load/sediment being carried and scraping against surfaces (1)' },
      { q: 'State three inputs into a drainage basin system.', marks: 3, markScheme: '• Precipitation (1)\n• Solar energy (1)\n• Sediment from weathering/mass movement (1)\n• Geological inputs e.g. springs (1) (any three)' },

      // 4-6 mark questions (15)
      { q: 'Describe the formation of a waterfall and plunge pool.', marks: 4, markScheme: '• River flows over band of resistant rock overlying softer rock (1)\n• Softer rock eroded more quickly by hydraulic action/abrasion (1)\n• Undercutting creates an overhang of harder rock (1)\n• Overhang collapses and waterfall retreats upstream (1)\n• Plunge pool formed at base by erosion from falling water and swirling sediment (1) (max 4)' },
      { q: 'Explain how freeze-thaw weathering breaks down rock in upland landscapes.', marks: 4, markScheme: '• Water enters cracks/joints in rock (1)\n• Water freezes when temperature drops below 0°C and expands by approximately 9% (1)\n• Expansion exerts pressure on surrounding rock (1)\n• Repeated freeze-thaw cycles weaken rock until fragments break off (1)\n• Produces angular scree/talus at base of slopes (1) (max 4)' },
      { q: 'Explain two ways in which vegetation influences slope processes.', marks: 4, markScheme: '• Root systems bind soil together, increasing cohesion and reducing mass movement (1)\n• Developed explanation e.g. deep roots of trees anchor soil to bedrock (1)\n• Vegetation intercepts rainfall, reducing amount reaching the ground surface (1)\n• Developed explanation e.g. reduces infiltration rate and therefore pore water pressure (1)' },
      { q: 'Describe the characteristics of a floodplain and explain how it is formed.', marks: 6, markScheme: '• Wide, flat area of land either side of a river in the lower course (1)\n• Composed of alluvium/river-deposited sediment (1)\n• Formed by lateral erosion as river meanders (1)\n• Meanders migrate across the valley floor over time (1)\n• During flooding, river overtops banks and deposits sediment (1)\n• Coarser material deposited near channel forming levees, finer material further away (1)' },
      { q: 'Explain how longshore drift transports sediment along a coastline.', marks: 4, markScheme: '• Waves approach the coast at an angle determined by prevailing wind direction (1)\n• Swash carries sediment up the beach at this angle (1)\n• Backwash drags sediment back down the beach at right angles due to gravity (1)\n• Repeated process moves sediment in a zigzag pattern along the coast (1)\n• Accumulation occurs where energy decreases e.g. at a spit (1) (max 4)' },
      { q: 'Describe and explain the formation of an ox-bow lake.', marks: 6, diagram: true, markScheme: '• Meander neck becomes progressively narrower due to erosion on outside bends (1)\n• Hydraulic action and abrasion erode the outer banks (1)\n• During a flood event, the river breaks through the narrow neck (1)\n• The river takes the shorter, straighter course (1)\n• Deposition seals off the old meander loop (1)\n• The cut-off meander becomes an ox-bow lake which gradually dries up (1)\n• Credit annotated diagram showing stages of formation' },
      { q: 'Explain two ways in which geology influences coastal landforms.', marks: 4, markScheme: '• Rock type affects resistance to erosion e.g. granite is more resistant than clay (1)\n• Developed explanation e.g. leads to differential erosion creating headlands and bays (1)\n• Rock structure e.g. joints, bedding planes create lines of weakness (1)\n• Developed explanation e.g. hydraulic action exploits joints to form caves, arches, stacks (1)' },
      { q: 'Describe the landforms associated with glacial erosion in an upland area.', marks: 6, diagram: true, markScheme: '• Corries/cirques: armchair-shaped hollows formed by rotational ice movement and plucking (1)\n• Aretes: knife-edge ridges formed between two adjacent corries (1)\n• Pyramidal peaks: pointed summits formed where three or more corries erode back-to-back (1)\n• U-shaped valleys/glacial troughs: steep-sided, flat-floored valleys formed by powerful glacial abrasion (1)\n• Hanging valleys: tributary valleys left high above the main valley floor (1)\n• Truncated spurs: interlocking spurs removed by glacial erosion (1)\n• Credit annotated diagram of glacial features' },
      { q: 'Explain the concept of sediment cells and why they are important for coastal management.', marks: 6, markScheme: '• Sediment cells are self-contained sections of coastline (1)\n• Within which sediment movement operates as a closed system (1)\n• Each cell has sources (inputs), transfers, and sinks (outputs) of sediment (1)\n• England and Wales divided into 11 major sediment cells (1)\n• Important because actions in one part of a cell affect other parts (1)\n• Management decisions should consider the whole cell to avoid unintended consequences (1)\n• E.g. building groynes in one area may starve another area of sediment (1) (max 6)' },
      { q: 'Explain how a spit is formed.', marks: 4, markScheme: '• Longshore drift transports sediment along the coastline (1)\n• Where the coastline changes direction e.g. at a river mouth, sediment continues to be deposited in the original direction (1)\n• Over time the deposited material extends outwards forming a ridge/spit (1)\n• The end may curve due to wave refraction or secondary wind/wave direction (1)\n• Salt marsh may develop in the sheltered area behind the spit (1) (max 4)' },
      { q: 'Explain how the drainage basin hydrological cycle operates as an open system.', marks: 6, markScheme: '• Open system has inputs and outputs that cross the system boundary (1)\n• Inputs: precipitation entering the drainage basin (1)\n• Outputs: river discharge to the sea, evapotranspiration to the atmosphere (1)\n• Stores: soil moisture, groundwater, channel storage, interception (1)\n• Transfers/flows: infiltration, percolation, throughflow, overland flow, groundwater flow (1)\n• The water balance equation: P = Q + E +/- S (1)\n• Seasonal variations in inputs and outputs create changes in storage (1) (max 6)' },
      { q: 'Describe the features and formation of a storm beach.', marks: 4, markScheme: '• A ridge of coarse sediment found at the back of the beach (1)\n• Located above the normal high tide line (1)\n• Formed during storm conditions when powerful destructive waves throw large material inland (1)\n• Strong swash deposits sediment at the highest point waves can reach (1)\n• May contain large pebbles, cobbles and debris (1) (max 4)' },
      { q: 'Explain two ways in which human activity can alter the sediment budget of a coastal system.', marks: 4, markScheme: '• Dam construction on rivers reduces sediment supply to the coast (1)\n• Developed explanation e.g. less sediment for natural beach replenishment leading to erosion (1)\n• Coastal defences such as groynes trap sediment, reducing supply downdrift (1)\n• Developed explanation e.g. can lead to increased erosion in adjacent areas (1)' },
      { q: 'Describe how a levee forms naturally alongside a river channel.', marks: 4, markScheme: '• During flood events the river overtops its banks (1)\n• As water spills onto the floodplain there is a sudden reduction in velocity (1)\n• The coarsest/heaviest sediment is deposited first, nearest to the channel (1)\n• Repeated flooding builds up raised banks/levees on either side of the channel (1)' },
      { q: 'Explain how sub-aerial processes contribute to cliff recession on a coastline.', marks: 5, markScheme: '• Sub-aerial processes are land-based processes that act on the cliff face (1)\n• Chemical weathering e.g. carbonation dissolves limestone, weakening the rock (1)\n• Mechanical weathering e.g. freeze-thaw shatters exposed rock faces (1)\n• Biological weathering e.g. plant roots widen joints and cracks (1)\n• Mass movement e.g. rotational slumping moves saturated material downslope (1)\n• These processes weaken the cliff making it more susceptible to wave attack at the base (1) (max 5)' },

      // 8-9 mark questions (10)
      { q: 'Explain how the interaction of different processes creates distinctive coastal landforms. Use examples in your answer.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of how multiple processes interact to create specific landforms. Clear use of examples. Logical and well-structured.\nLevel 2 (4-6 marks): Some explanation of process interaction with some examples. Partial development of ideas.\nLevel 1 (1-3 marks): Basic description of processes or landforms with limited linkage.\n\nIndicative content:\n• Erosion processes (hydraulic action, abrasion, attrition, solution) and how they combine\n• Weathering processes weakening rock before wave attack\n• Formation of caves, arches, stacks, stumps through progressive erosion of weaknesses\n• Role of geology: concordant vs discordant coastlines creating different landform assemblages\n• Headlands and bays from differential erosion\n• Depositional landforms from constructive wave action and longshore drift\n• Named examples e.g. Old Harry Rocks, Durdle Door, Chesil Beach' },
      { q: 'Explain how climate influences the processes and landforms found in a river drainage basin.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed and well-developed explanation linking climate to specific processes and resulting landforms. Uses terminology accurately.\nLevel 2 (4-6 marks): Some links between climate and processes/landforms. Partial development.\nLevel 1 (1-3 marks): Basic points about climate and rivers with limited explanation.\n\nIndicative content:\n• Precipitation amount and intensity affects discharge, flood frequency, and erosion rates\n• Temperature influences weathering type (freeze-thaw in cold, chemical in tropical)\n• Seasonal variations create different flow regimes\n• Arid climates: flash floods, ephemeral streams, steep-sided wadis\n• Tropical climates: high rates of chemical weathering, deep regolith, high sediment loads\n• Glacial climates: meltwater channels, glacial landforms, periglacial processes\n• Climate change altering discharge patterns and sea level affecting base level' },
      { q: 'Explain how geological structure influences the development of upland landscapes.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple ways geology influences landscape, with clear links between structure and landforms. Well-exemplified.\nLevel 2 (4-6 marks): Some explanation of geological influence with partial development.\nLevel 1 (1-3 marks): Basic identification of geological factors with limited explanation.\n\nIndicative content:\n• Rock type: resistance to erosion creates differential landscapes\n• Igneous rocks (granite) create tors and moorland landscapes\n• Sedimentary rocks create scarp and vale topography\n• Permeability affects drainage patterns and surface features\n• Joints and faults create lines of weakness exploited by weathering and erosion\n• Bedding planes influence slope angles and mass movement\n• Folding and faulting create structural landforms\n• Examples: Lake District, Dartmoor, Yorkshire Dales' },
      { q: 'Explain how human activity can disrupt the natural functioning of landscape systems. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation with multiple clear examples of how human activity disrupts system functioning. Well-structured argument.\nLevel 2 (4-6 marks): Some explanation with examples but partial development.\nLevel 1 (1-3 marks): Basic identification of human impacts with limited explanation.\n\nIndicative content:\n• Deforestation increasing runoff and erosion rates\n• Urbanisation altering drainage basin hydrology (impermeable surfaces)\n• Dam construction trapping sediment, altering downstream processes\n• Coastal defences interrupting longshore drift and sediment supply\n• Agricultural practices increasing soil erosion\n• Mining and quarrying altering slope stability\n• Climate change as an indirect human impact on processes\n• Specific named examples for each impact discussed' },
      { q: 'Explain how mass movement processes shape slopes in different landscape settings.', marks: 9, markScheme: 'Level 3 (7-9 marks): Thorough explanation of mass movement types in different settings. Clear understanding of factors controlling type and rate. Well-exemplified.\nLevel 2 (4-6 marks): Describes several mass movement types with some explanation of controls.\nLevel 1 (1-3 marks): Basic description of one or two types with limited context.\n\nIndicative content:\n• Rockfall on steep cliff faces (coastal and inland)\n• Rotational slumping on clay cliffs e.g. Holderness coast\n• Soil creep on moderate slopes (terracettes)\n• Solifluction in periglacial environments\n• Mudflows and debris flows following heavy rainfall\n• Factors: slope angle, rock type, water content, vegetation cover, undercutting\n• Relationship between mass movement and other processes (weathering, erosion)\n• Role of triggering events (heavy rain, earthquakes, wave undercutting)' },
      { q: 'Explain how changes in sea level affect coastal landscapes. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of both rising and falling sea level effects with clear examples. Links to specific landforms.\nLevel 2 (4-6 marks): Some explanation of sea level change effects with partial examples.\nLevel 1 (1-3 marks): Basic identification of sea level effects.\n\nIndicative content:\n• Eustatic change: global sea level change due to ice volume changes\n• Isostatic change: local land level change due to ice loading/unloading\n• Submergent features: rias (drowned river valleys e.g. Kingsbridge estuary), fjords (drowned glacial valleys e.g. Milford Sound)\n• Emergent features: raised beaches, relict cliffs\n• Current sea level rise threatening low-lying coasts\n• Impact on erosion rates and coastal squeeze\n• Historical context: post-glacial sea level rise and isostatic rebound' },
      { q: 'Explain how the water balance and river regime of a drainage basin are influenced by physical and human factors.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation covering both physical and human factors with clear links to water balance and regime. Uses terminology accurately.\nLevel 2 (4-6 marks): Some factors explained with partial linkage to water balance.\nLevel 1 (1-3 marks): Basic identification of factors.\n\nIndicative content:\n• Water balance equation: P = Q + E +/- S\n• Climate: precipitation patterns determine input volume and timing\n• Temperature affects evapotranspiration rates\n• Geology: permeable rocks increase groundwater storage, reduce surface runoff\n• Vegetation: intercepts precipitation, increases evapotranspiration\n• Soil type: affects infiltration capacity\n• Human factors: urbanisation creates impermeable surfaces, increases flashy regimes\n• Abstraction reduces discharge, dam construction regulates flow\n• Land use change e.g. deforestation alters interception and infiltration' },
      { q: 'Explain how different coastal management strategies can create conflicts between stakeholders. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple strategies and conflicts with well-developed examples.\nLevel 2 (4-6 marks): Some strategies and conflicts discussed with partial examples.\nLevel 1 (1-3 marks): Basic identification of strategies or conflicts.\n\nIndicative content:\n• Hard engineering (sea walls, groynes, rock armour) protects one area but may increase erosion elsewhere\n• Managed retreat/realignment: conflict between environmental benefits and loss of agricultural/residential land\n• Hold the line vs no active intervention: economic costs vs environmental sustainability\n• Shoreline Management Plans and their prioritisation decisions\n• Stakeholders: residents, farmers, businesses, environmental groups, local authorities\n• Named examples e.g. Happisburgh, Medmerry managed realignment\n• Cost-benefit analysis and who bears the costs vs who benefits' },
      { q: 'Explain the processes involved in the formation of a glacial trough and its associated features.', marks: 9, diagram: true, markScheme: 'Level 3 (7-9 marks): Detailed explanation of glacial processes creating the trough and associated features. Accurate use of terminology. Well-structured.\nLevel 2 (4-6 marks): Some processes and features explained with partial development.\nLevel 1 (1-3 marks): Basic description of a glacial trough.\n\nIndicative content:\n• Pre-existing river valley occupied by glacier\n• Abrasion by debris-laden ice deepens and widens the valley\n• Plucking removes rock from valley sides and floor\n• Freeze-thaw weathering above glacier contributes debris\n• Result: U-shaped cross-profile with steep sides and flat floor\n• Associated features: hanging valleys, truncated spurs, ribbon lakes\n• Misfit streams on valley floor\n• Post-glacial modification: scree, alluvial fans\n• Credit annotated diagram of glacial trough features' },
      { q: 'Explain how feedback mechanisms operate within landscape systems and why they are important.', marks: 8, markScheme: 'Level 3 (7-8 marks): Clear understanding of both positive and negative feedback with landscape examples. Links to system stability/instability.\nLevel 2 (4-6 marks): Some understanding of feedback with partial examples.\nLevel 1 (1-3 marks): Basic description with limited understanding of feedback.\n\nIndicative content:\n• Negative feedback: counteracts change, restores equilibrium e.g. increased erosion steepens slope, triggering mass movement that reduces angle\n• Positive feedback: amplifies change, moves system further from equilibrium e.g. coastal erosion removes beach material, exposing cliffs to more wave attack, increasing erosion\n• Thresholds: points at which systems shift between states\n• Dynamic equilibrium maintained by negative feedback\n• Human activity can trigger positive feedback loops\n• Importance for understanding landscape change and management decisions\n• Timescales over which feedback operates' },

      // 12-20 mark questions (5)
      { q: 'Assess the relative importance of different factors that influence the development of coastal landscapes. Use examples.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough and balanced assessment of multiple factors with clear judgement of relative importance. Well-integrated examples throughout. Sustained, logical argument.\nLevel 3 (9-12 marks): Clear assessment of several factors with some judgement. Good use of examples.\nLevel 2 (5-8 marks): Describes factors with limited assessment. Some examples.\nLevel 1 (1-4 marks): Basic description of one or two factors.\n\nIndicative content:\n• Geology: rock type and structure creating concordant/discordant coastlines\n• Wave processes: constructive vs destructive, fetch, wave energy\n• Weathering and mass movement: sub-aerial processes\n• Sea level change: eustatic and isostatic\n• Human activity: coastal management, development, land use\n• Climate and weather: storm frequency, precipitation\n• Time: landscapes as products of long-term process interaction\n• Assessment of which factors are most influential and in what contexts\n• Named examples: Dorset coast, Holderness, etc.' },
      { q: '"River landscapes are shaped more by erosion than deposition." Discuss this statement with reference to examples you have studied.', marks: 16, markScheme: 'Level 4 (13-16 marks): Balanced discussion considering both erosion and deposition across different parts of the river. Clear judgement reached. Well-exemplified.\nLevel 3 (9-12 marks): Discussion of both erosion and deposition with some balance and examples.\nLevel 2 (5-8 marks): Describes erosion and/or deposition with limited discussion.\nLevel 1 (1-4 marks): Basic description with no real discussion.\n\nIndicative content:\nErosion:\n• Upper course dominance: V-shaped valleys, waterfalls, gorges\n• Vertical and lateral erosion creating valley forms\n• Processes: hydraulic action, abrasion, attrition, solution\nDeposition:\n• Lower course features: floodplains, levees, deltas\n• Mid-course: point bars on meander bends\n• Ox-bow lake formation involves both erosion and deposition\nBalance:\n• Different sections of river dominated by different processes\n• Both are essential and interconnected\n• Neither can be considered more important overall\n• Human modification alters the natural balance\n• Named river examples throughout' },
      { q: 'Evaluate the effectiveness of different approaches to managing river flooding. Refer to examples.', marks: 12, markScheme: 'Level 4 (10-12 marks): Thorough evaluation of multiple approaches with clear judgement of effectiveness. Well-supported by examples.\nLevel 3 (7-9 marks): Evaluation of several approaches with some judgement and examples.\nLevel 2 (4-6 marks): Describes approaches with limited evaluation.\nLevel 1 (1-3 marks): Basic description of one or two approaches.\n\nIndicative content:\n• Hard engineering: dams, embankments, channel straightening, flood walls\n• Soft engineering: floodplain zoning, afforestation, washlands, sustainable drainage\n• Advantages and disadvantages of each approach\n• Cost-benefit analysis\n• Environmental sustainability\n• Integrated catchment management\n• Named examples: e.g. River Thames Barrier, Pickering "Slowing the Flow"\n• Judgement on most effective combination of approaches' },
      { q: 'To what extent do physical processes operate as a system in shaping landscapes? Use examples from two contrasting landscape types.', marks: 20, markScheme: 'Level 5 (17-20 marks): Sophisticated understanding of systems concepts applied to two contrasting landscapes. Sustained evaluation with clear judgement. Exemplary use of examples.\nLevel 4 (13-16 marks): Detailed application of systems concepts to two landscapes with good evaluation.\nLevel 3 (9-12 marks): Some application of systems concepts with partial evaluation.\nLevel 2 (5-8 marks): Describes processes in landscapes with limited systems thinking.\nLevel 1 (1-4 marks): Basic description with minimal systems understanding.\n\nIndicative content:\n• Systems concepts: inputs, outputs, stores, transfers, feedback, equilibrium\n• Landscape 1 (e.g. coastal): wave energy inputs, sediment transfers, depositional outputs\n• Landscape 2 (e.g. glacial): ice/snow inputs, erosion/transport transfers, depositional outputs\n• Interconnection of processes within each system\n• Feedback mechanisms: positive and negative\n• Role of thresholds and tipping points\n• Extent to which landscapes function as open systems\n• Human disruption of natural systems\n• Time scales and the degree to which equilibrium is achieved\n• Contrasts and comparisons between the two landscape types' },
      { q: '"Coastal management should always work with natural processes rather than against them." To what extent do you agree with this statement?', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation considering both hard and soft engineering with clear, justified judgement. Well-supported by specific examples.\nLevel 3 (9-12 marks): Discussion of both approaches with some evaluation and examples.\nLevel 2 (5-8 marks): Describes management approaches with limited evaluation.\nLevel 1 (1-4 marks): Basic description of coastal management.\n\nIndicative content:\nWorking with natural processes:\n• Managed realignment e.g. Medmerry\n• Beach nourishment maintaining natural defence\n• Sand dune stabilisation\n• Sustainable and long-term\nWorking against natural processes:\n• Sea walls, groynes, rock armour\n• Can be effective short-term for high-value areas\n• May cause problems elsewhere (terminal groyne effect)\n• Expensive to maintain\nEvaluation:\n• Context matters: urban vs rural, economic value\n• Combination approaches often most effective\n• SMP approach to decision-making\n• Climate change increasing need for adaptive strategies' },
    ],
  },

  '1.2': {
    name: "Earth's Life Support Systems",
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two ways in which water is stored in the global hydrological cycle.', marks: 2, markScheme: '• Oceans/seas (1)\n• Ice caps/glaciers (1)\n• Groundwater (1)\n• Atmosphere (1)\n• Rivers/lakes (1) (any two)' },
      { q: 'Define the term "carbon sink".', marks: 2, markScheme: '• A natural or artificial reservoir/store (1)\n• That absorbs and stores carbon from the atmosphere, reducing atmospheric CO2 concentration (1)' },
      { q: 'State three processes that transfer carbon between stores.', marks: 3, markScheme: '• Photosynthesis (1)\n• Respiration (1)\n• Combustion (1)\n• Decomposition (1)\n• Weathering (1) (any three)' },
      { q: 'State two ways in which water moves from the atmosphere to the land surface.', marks: 2, markScheme: '• Precipitation (rain, snow, hail, sleet) (1)\n• Condensation/dew formation (1)' },
      { q: 'Define the term "evapotranspiration".', marks: 2, markScheme: '• The combined process of evaporation from surfaces (1)\n• And transpiration from plants releasing water vapour to the atmosphere (1)' },
      { q: 'State two reasons why the Amazon rainforest is important as a carbon store.', marks: 2, markScheme: '• Contains vast biomass which stores carbon in living tissue (1)\n• Soils contain large amounts of organic carbon (1)\n• Absorbs CO2 through photosynthesis at high rates due to year-round growing season (1) (any two)' },
      { q: 'State two human activities that release carbon into the atmosphere.', marks: 2, markScheme: '• Burning fossil fuels (1)\n• Deforestation/burning of vegetation (1)\n• Cement production (1)\n• Agriculture e.g. livestock, rice paddies (1) (any two)' },
      { q: 'Define the term "residence time" in the carbon cycle.', marks: 2, markScheme: '• The average length of time a carbon atom/molecule remains in a particular store (1)\n• Before being transferred to another store (1)' },
      { q: 'State two ways in which the ocean acts as a carbon store.', marks: 2, markScheme: '• Dissolved CO2 in ocean water (1)\n• Carbon locked in marine organisms/shells/coral (1)\n• Carbon in ocean floor sediments (1) (any two)' },
      { q: 'State the difference between blue water and green water.', marks: 3, markScheme: '• Blue water is liquid water in rivers, lakes and aquifers (1)\n• Green water is water held in soil and vegetation (1)\n• Green water is returned to the atmosphere via evapotranspiration (1)' },

      // 4-6 mark questions (15)
      { q: 'Describe how the carbon cycle links the atmosphere, biosphere, and lithosphere.', marks: 6, markScheme: '• Atmosphere contains CO2 which is absorbed by plants through photosynthesis (atmosphere to biosphere) (1)\n• Carbon stored in living biomass of plants and animals (1)\n• Dead organic matter decomposes, releasing carbon back to atmosphere or into soils (1)\n• Over geological timescales, organic matter becomes fossil fuels in lithosphere (1)\n• Weathering of carbonate rocks releases carbon (lithosphere to atmosphere) (1)\n• Volcanic eruptions release CO2 from lithosphere to atmosphere (1)' },
      { q: 'Explain how deforestation affects both the carbon and water cycles.', marks: 6, markScheme: '• Carbon cycle: removal of trees reduces photosynthetic uptake of CO2 (1)\n• Burning of cleared vegetation releases stored carbon as CO2 (1)\n• Decomposition of remaining organic matter releases further carbon (1)\n• Water cycle: reduced interception means more water reaches ground surface (1)\n• Reduced transpiration decreases local atmospheric moisture/precipitation (1)\n• Increased surface runoff and reduced infiltration (1)\n• Potential disruption to local rainfall patterns (1) (max 6)' },
      { q: 'Explain the role of photosynthesis and respiration in the carbon cycle.', marks: 4, markScheme: '• Photosynthesis absorbs CO2 from the atmosphere (1)\n• Plants use CO2 and water to produce glucose and oxygen, storing carbon in biomass (1)\n• Respiration by all living organisms releases CO2 back to the atmosphere (1)\n• These two processes create a short-term carbon cycle between atmosphere and biosphere (1)\n• Balance between photosynthesis and respiration affects net carbon flux (1) (max 4)' },
      { q: 'Explain how ocean circulation transfers water and energy around the globe.', marks: 6, markScheme: '• Thermohaline circulation driven by differences in temperature and salinity (1)\n• Cold, dense water sinks at high latitudes (e.g. North Atlantic) (1)\n• Deep water flows towards equator, warm surface water flows poleward (1)\n• Transfers heat energy from tropics to higher latitudes (1)\n• Surface currents driven by wind patterns (1)\n• Upwelling brings cold, nutrient-rich water to surface (1)\n• Links to atmospheric circulation patterns and climate regulation (1) (max 6)' },
      { q: 'Describe how the water cycle operates at the global scale.', marks: 6, diagram: true, markScheme: '• Evaporation from oceans (main source) and land surfaces (1)\n• Water vapour transported in atmosphere by wind/air masses (1)\n• Condensation forms clouds when air cools (1)\n• Precipitation falls as rain, snow, sleet, hail (1)\n• Surface runoff and groundwater flow return water to oceans (1)\n• Driven by solar energy which powers evaporation (1)\n• Credit annotated diagram showing the cycle' },
      { q: 'Explain how the formation of fossil fuels represents a long-term transfer in the carbon cycle.', marks: 4, markScheme: '• Organic matter from dead plants and marine organisms accumulates (1)\n• Buried under layers of sediment over millions of years (1)\n• Heat and pressure transform organic material into coal, oil, or natural gas (1)\n• Carbon is effectively locked away in the lithosphere for geological timescales (1)\n• Removes carbon from the fast/active carbon cycle (1) (max 4)' },
      { q: 'Explain how changes in the cryosphere affect global sea levels.', marks: 6, markScheme: '• Melting of land-based ice sheets (Greenland, Antarctica) adds water to oceans (1)\n• This is eustatic sea level rise (1)\n• Melting glaciers also contribute additional water (1)\n• Thermal expansion of warming ocean water further increases sea levels (1)\n• Melting of sea ice does not directly raise sea levels (already displacing water) (1)\n• But reduces albedo, accelerating warming through positive feedback (1)\n• Isostatic adjustment as land rises after ice removal (1) (max 6)' },
      { q: 'Explain two ways in which weathering contributes to the carbon cycle.', marks: 4, markScheme: '• Chemical weathering of silicate rocks: CO2 dissolved in rainwater forms carbonic acid which reacts with silicate minerals (1)\n• This removes CO2 from the atmosphere and transfers it to dissolved carbonates in rivers/oceans (1)\n• Carbonation weathering of limestone: carbonic acid dissolves calcium carbonate (1)\n• Carbon is transferred from the lithosphere to the hydrosphere as dissolved calcium bicarbonate (1)' },
      { q: 'Explain how the water cycle is influenced by changes in temperature.', marks: 5, markScheme: '• Higher temperatures increase evaporation rates from oceans and land surfaces (1)\n• Warmer atmosphere holds more water vapour (7% more per 1°C rise) (1)\n• Can lead to more intense precipitation events (1)\n• Changes to snowfall/snowmelt patterns and timing (1)\n• Melting permafrost releases stored water and methane (1)\n• Changes to vegetation and therefore transpiration patterns (1) (max 5)' },
      { q: 'Describe the role of the ocean in the global carbon cycle.', marks: 6, markScheme: '• Oceans absorb approximately 25-30% of anthropogenic CO2 emissions (1)\n• CO2 dissolves in surface waters (physical/solubility pump) (1)\n• Marine organisms use dissolved carbon for shells and photosynthesis (biological pump) (1)\n• Dead organisms sink, transferring carbon to deep ocean (1)\n• Ocean sediments store carbon long-term in carbonate rocks (1)\n• Ocean circulation distributes carbon between surface and deep waters (1)\n• Warming reduces ocean\'s ability to absorb CO2 (1) (max 6)' },
      { q: 'Explain how feedback loops in the carbon cycle can accelerate climate change.', marks: 6, markScheme: '• Warming melts permafrost releasing methane (a potent greenhouse gas) (1)\n• This causes further warming, which melts more permafrost (positive feedback) (1)\n• Warming oceans release dissolved CO2, increasing atmospheric concentration (1)\n• Reduced ice cover lowers albedo, increasing absorption of solar radiation (1)\n• Forest dieback from drought reduces photosynthetic CO2 absorption (1)\n• Increased decomposition rates in warmer soils release more CO2 (1)\n• Each feedback amplifies the original warming signal (1) (max 6)' },
      { q: 'Explain why tropical rainforests have a major role in both the carbon and water cycles.', marks: 6, markScheme: '• High rates of photosynthesis due to year-round warmth and sunlight absorb large amounts of CO2 (1)\n• Store vast amounts of carbon in biomass (estimated 250 billion tonnes) (1)\n• Rapid decomposition recycles carbon through the system (1)\n• High transpiration rates contribute significant moisture to the atmosphere (1)\n• Generate convectional rainfall through local moisture recycling (1)\n• Interception and root uptake regulate water flow through the system (1)' },
      { q: 'Describe how human activities have altered the balance of the global carbon cycle.', marks: 5, markScheme: '• Burning fossil fuels releases carbon that was stored in the lithosphere over millions of years (1)\n• Deforestation reduces carbon uptake by photosynthesis and releases stored carbon (1)\n• Agriculture releases carbon through soil disturbance and livestock emissions (1)\n• Cement production releases CO2 from calcium carbonate (1)\n• Result is atmospheric CO2 rising from ~280 ppm (pre-industrial) to over 420 ppm (1)' },
      { q: 'Explain the concept of the water balance and how it varies seasonally in the UK.', marks: 5, markScheme: '• Water balance: P = Q + E +/- S (1)\n• In summer: higher temperatures increase evapotranspiration (1)\n• Soil moisture deficit develops as evapotranspiration exceeds precipitation (1)\n• In autumn: precipitation exceeds evapotranspiration, soil moisture recharge begins (1)\n• In winter/spring: soil moisture surplus, high river discharge, groundwater recharge (1)' },
      { q: 'Explain how wetlands function as both carbon and water stores.', marks: 4, markScheme: '• Waterlogged conditions slow decomposition of organic matter (1)\n• Carbon accumulates as peat over hundreds/thousands of years (1)\n• Wetlands store large volumes of water, reducing flood risk downstream (1)\n• Regulate water flow by slowly releasing water over time (1)\n• When drained, stored carbon is exposed to air and oxidises, releasing CO2 (1) (max 4)' },

      // 8-9 mark questions (10)
      { q: 'Explain how human activities are changing the global carbon cycle and assess the potential consequences.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple human impacts with clear assessment of consequences. Well-structured argument.\nLevel 2 (4-6 marks): Some explanation of human impacts with partial assessment.\nLevel 1 (1-3 marks): Basic description of human impacts.\n\nIndicative content:\n• Fossil fuel combustion releasing stored carbon\n• Deforestation reducing carbon sinks\n• Agriculture and land use change\n• Cement production\n• Consequences: enhanced greenhouse effect, global warming\n• Ocean acidification from increased dissolved CO2\n• Positive feedback loops amplifying change\n• Impacts on ecosystems, weather patterns, sea levels\n• Carbon cycle tipping points e.g. Amazon dieback, permafrost thaw' },
      { q: 'Explain the links between the water cycle and the carbon cycle. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple links between cycles with clear examples. Shows understanding of interdependence.\nLevel 2 (4-6 marks): Some links identified with partial explanation.\nLevel 1 (1-3 marks): Basic identification of one or two links.\n\nIndicative content:\n• Photosynthesis requires water and absorbs carbon\n• Weathering: water dissolves CO2, forming carbonic acid that weathers rocks\n• Ocean absorption of CO2 depends on temperature, circulation\n• Vegetation links both cycles (transpiration and carbon storage)\n• Deforestation disrupts both cycles simultaneously\n• Permafrost: frozen water traps carbon; thawing releases both\n• Cloud formation and albedo effects\n• Precipitation dissolves atmospheric CO2' },
      { q: 'Explain how the global distribution of water resources is influenced by physical and human factors.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of both physical and human factors with clear examples. Balanced coverage.\nLevel 2 (4-6 marks): Some factors explained with partial examples.\nLevel 1 (1-3 marks): Basic identification of factors.\n\nIndicative content:\nPhysical factors:\n• Climate/precipitation patterns (ITCZ, rain shadow)\n• Geology (aquifer availability)\n• Relief and drainage patterns\n• Seasonal variations\nHuman factors:\n• Population distribution and demand\n• Agricultural irrigation demands\n• Industrial water use\n• Water infrastructure (dams, wells, pipelines)\n• Pollution reducing usable supply\n• Examples of water surplus and deficit regions' },
      { q: 'Explain how the carbon cycle operates over different timescales.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of carbon cycling at different timescales with clear examples. Accurate use of terminology.\nLevel 2 (4-6 marks): Some explanation with partial coverage of timescales.\nLevel 1 (1-3 marks): Basic description with limited timescale awareness.\n\nIndicative content:\nShort-term (days-years):\n• Photosynthesis/respiration\n• Seasonal vegetation changes\n• Decomposition of organic matter\nMedium-term (decades-centuries):\n• Forest growth and carbon accumulation\n• Soil carbon development\n• Ocean absorption of CO2\nLong-term (millions of years):\n• Fossil fuel formation\n• Lithification of marine sediments\n• Weathering of carbonate rocks\n• Volcanic outgassing\n• Tectonic carbon cycle' },
      { q: 'Explain how changes to the cryosphere could trigger positive feedback mechanisms in both the carbon and water cycles.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of feedback mechanisms in both cycles triggered by cryosphere changes. Clear chain of causation.\nLevel 2 (4-6 marks): Some feedback mechanisms identified with partial explanation.\nLevel 1 (1-3 marks): Basic description of cryosphere changes.\n\nIndicative content:\nCarbon cycle feedbacks:\n• Permafrost thaw releases methane and CO2\n• Enhanced greenhouse effect causes more warming and more thaw\n• Reduced vegetation in tundra reduces carbon uptake\nWater cycle feedbacks:\n• Ice-albedo feedback: less ice, less reflection, more warming, more melting\n• More open ocean increases evaporation\n• Changed precipitation patterns\n• Sea level rise from ice sheet melting\n• Combined effect: warming accelerates beyond initial forcing' },
      { q: 'Explain how ocean-atmosphere interactions regulate the global water cycle.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple ocean-atmosphere interactions and their role in water cycling. Well-structured.\nLevel 2 (4-6 marks): Some interactions explained with partial development.\nLevel 1 (1-3 marks): Basic identification of interactions.\n\nIndicative content:\n• Evaporation from ocean surface provides main input of moisture to atmosphere\n• Driven by solar energy and wind\n• Warm ocean currents increase evaporation in certain regions\n• Atmospheric circulation patterns (Hadley, Ferrel, Polar cells) redistribute moisture\n• ENSO events alter Pacific circulation and global rainfall patterns\n• Thermohaline circulation and its role in heat/moisture transport\n• Sea surface temperatures influence storm intensity and precipitation\n• Monsoon systems driven by land-sea temperature contrasts' },
      { q: 'Explain why the management of tropical rainforests is important for maintaining the stability of global carbon and water cycles.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation linking rainforest management to both cycle stability. Well-reasoned argument with examples.\nLevel 2 (4-6 marks): Some links between management and cycle stability.\nLevel 1 (1-3 marks): Basic description of rainforest importance.\n\nIndicative content:\n• Rainforests as major carbon sinks storing 250+ billion tonnes\n• Deforestation releases stored carbon and reduces future uptake\n• Tipping point: Amazon could switch from carbon sink to source\n• Transpiration generates 50-80% of regional rainfall through moisture recycling\n• Loss of transpiration reduces rainfall, increasing drought risk\n• Soil carbon exposed when forest cleared\n• Management approaches: REDD+, protected areas, sustainable forestry\n• International significance: global climate regulation\n• Conflict between development needs and conservation' },
      { q: 'Explain how fossil fuel combustion has disrupted the natural balance of the carbon cycle.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of how fossil fuel use has disrupted the carbon cycle with clear understanding of the scale of change.\nLevel 2 (4-6 marks): Some explanation with partial development.\nLevel 1 (1-3 marks): Basic identification of disruption.\n\nIndicative content:\n• Fossil fuels contain carbon stored over millions of years\n• Combustion releases this carbon as CO2 in decades\n• Approximately 36 billion tonnes CO2 emitted annually\n• Natural sinks cannot absorb all emissions\n• Atmospheric CO2 increased from 280 to 420+ ppm since industrialisation\n• Rate of release far exceeds natural geological carbon fluxes\n• Enhanced greenhouse effect and global warming\n• Ocean acidification as oceans absorb excess CO2\n• Disrupted feedback loops and potential tipping points' },
      { q: 'Explain how the water cycle is important for supporting life on Earth.', marks: 8, markScheme: 'Level 3 (7-8 marks): Comprehensive explanation of multiple ways the water cycle supports life. Well-developed with examples.\nLevel 2 (4-6 marks): Several ways explained with partial development.\nLevel 1 (1-3 marks): Basic points about water and life.\n\nIndicative content:\n• Freshwater supply for human consumption and agriculture\n• Maintains river, lake and wetland ecosystems\n• Regulates temperature through heat redistribution\n• Enables photosynthesis and plant growth\n• Nutrient cycling and transport\n• Soil formation and maintenance\n• Weather and climate regulation\n• Supports biodiversity in aquatic and terrestrial ecosystems\n• Only 2.5% of water is freshwater, cycling makes it available\n• Uneven distribution creates challenges for some regions' },
      { q: 'Explain how peatlands function as important carbon stores and assess the threats they face.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of peatland carbon storage and thorough assessment of threats. Well-exemplified.\nLevel 2 (4-6 marks): Some explanation of function and threats.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nCarbon storage function:\n• Waterlogged, acidic, anaerobic conditions slow decomposition\n• Partially decomposed plant material (sphagnum moss) accumulates as peat\n• UK peatlands store ~3.2 billion tonnes of carbon\n• Global peatlands store twice as much carbon as all forests combined\nThreats:\n• Drainage for agriculture exposes peat to air, causing oxidation and CO2 release\n• Peat extraction for horticulture\n• Overgrazing and erosion\n• Wildfire (increasing with climate change)\n• Climate change: warmer, drier conditions increase decomposition\n• Assessment of severity and management responses' },

      // 12-20 mark questions (5)
      { q: '"Human activity has fundamentally altered the global carbon cycle beyond recovery." To what extent do you agree with this statement?', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation with balanced consideration of evidence for and against. Clear, justified judgement. Well-supported throughout.\nLevel 3 (9-12 marks): Good evaluation with some balance and supporting evidence.\nLevel 2 (5-8 marks): Some relevant points but limited evaluation.\nLevel 1 (1-4 marks): Basic description with no real evaluation.\n\nIndicative content:\nEvidence of fundamental alteration:\n• Atmospheric CO2 at highest level in 800,000+ years\n• Rate of change unprecedented in geological record\n• Positive feedback loops may be irreversible (permafrost thaw, Amazon dieback)\n• Ocean acidification damaging marine carbon cycling\nEvidence against "beyond recovery":\n• Natural carbon sinks still functioning\n• Technology: carbon capture and storage potential\n• Reforestation and afforestation programmes\n• International agreements (Paris Agreement)\n• Carbon cycle has recovered from perturbations in geological past\nJudgement:\n• Timescale of recovery vs human timescales\n• Tipping points and thresholds\n• Difference between altered and "beyond recovery"' },
      { q: 'Assess the role of the oceans in regulating global climate through the carbon and water cycles.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough assessment covering both cycles with clear evaluation of the ocean\'s regulatory role. Well-integrated examples.\nLevel 3 (9-12 marks): Good coverage of both cycles with some assessment.\nLevel 2 (5-8 marks): Describes ocean processes with limited assessment.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nCarbon cycle:\n• Absorbs ~25% of anthropogenic CO2\n• Physical and biological carbon pumps\n• Deep ocean carbon storage\n• Ocean acidification reducing absorption capacity\nWater cycle:\n• Main source of atmospheric moisture through evaporation\n• Thermohaline circulation redistributes heat\n• El Nino/La Nina influence global weather\n• Sea surface temperatures drive storm systems\nRegulatory role:\n• Thermal inertia buffers climate change\n• But limits to ocean absorption capacity\n• Warming reduces solubility of CO2\n• Changes to circulation could have major consequences\n• Overall assessment of ocean\'s effectiveness as a regulator' },
      { q: 'Evaluate the strategies that can be used to manage the impacts of human activity on the global water cycle.', marks: 12, markScheme: 'Level 4 (10-12 marks): Thorough evaluation of multiple strategies with clear judgement of effectiveness. Supported by examples.\nLevel 3 (7-9 marks): Evaluation of several strategies with some judgement.\nLevel 2 (4-6 marks): Describes strategies with limited evaluation.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Water conservation and efficiency measures\n• Sustainable irrigation techniques\n• Reforestation to restore interception and transpiration\n• Wetland restoration for water storage and filtration\n• Desalination technology\n• Water recycling and treatment\n• International water sharing agreements\n• Reducing pollution of water sources\n• Managing urbanisation impacts (SuDS)\n• Evaluation of cost, feasibility, scale, sustainability' },
      { q: 'Discuss the extent to which the carbon and water cycles can be considered interdependent. Use examples from different scales.', marks: 20, markScheme: 'Level 5 (17-20 marks): Exceptional understanding of interdependence across scales. Sustained, coherent argument with sophisticated examples.\nLevel 4 (13-16 marks): Detailed discussion of interdependence at multiple scales with good examples.\nLevel 3 (9-12 marks): Some discussion of interdependence with examples.\nLevel 2 (5-8 marks): Describes both cycles with limited linkage.\nLevel 1 (1-4 marks): Basic description of one or both cycles.\n\nIndicative content:\nLocal scale:\n• Forest ecosystem: photosynthesis requires water, transpiration returns water, carbon stored in biomass\n• Peatlands: waterlogged conditions control carbon decomposition\nRegional scale:\n• Amazon rainforest: carbon storage depends on rainfall, transpiration generates rainfall\n• Deforestation disrupts both cycles simultaneously\nGlobal scale:\n• Ocean as a store for both carbon and water\n• Temperature changes affect both cycles\n• Climate change as an output of carbon cycle disruption affecting water cycle\n• Feedback mechanisms linking both cycles\nExtent of interdependence:\n• Can either cycle function independently?\n• Where are the strongest links?\n• Are there aspects that operate independently?\n• Implications for management: need to consider both cycles together' },
      { q: 'To what extent can management strategies successfully restore the natural balance of the carbon cycle? Refer to examples.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation of multiple strategies with clear judgement about their potential success. Well-supported by examples.\nLevel 3 (9-12 marks): Good range of strategies evaluated with some judgement.\nLevel 2 (5-8 marks): Describes strategies with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nStrategies:\n• Reforestation/afforestation (e.g. Bonn Challenge, Great Green Wall)\n• Peatland restoration (e.g. UK blanket bog rewetting)\n• Carbon capture and storage technology\n• Renewable energy transition reducing fossil fuel emissions\n• REDD+ protecting existing forests\n• Soil carbon management in agriculture\n• Ocean fertilisation proposals\nEvaluation:\n• Scale of interventions vs scale of the problem\n• Timescales for carbon sequestration vs rate of emissions\n• Cost and technological feasibility\n• Political will and international cooperation\n• Natural system resilience and tipping points\n• Overall judgement on whether balance can be restored' },
    ],
  },

  '1.3': {
    name: 'Hazardous Earth',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two primary hazards associated with volcanic eruptions.', marks: 2, markScheme: '• Lava flows (1)\n• Pyroclastic flows (1)\n• Ash fall (1)\n• Lahars (1)\n• Volcanic gases (1) (any two)' },
      { q: 'State two pieces of evidence used to support the theory of plate tectonics.', marks: 2, markScheme: '• Continental fit (jigsaw fit of continents e.g. South America and Africa) (1)\n• Matching fossil records across continents (1)\n• Matching rock types and geological structures (1)\n• Palaeomagnetism/magnetic striping on ocean floor (1) (any two)' },
      { q: 'Define the term "hazard risk".', marks: 2, markScheme: '• The probability/likelihood of a hazard event occurring (1)\n• And causing loss of life, injury, or damage to property/livelihoods (1)' },
      { q: 'State three factors that affect the severity of an earthquake\'s impact.', marks: 3, markScheme: '• Magnitude of the earthquake (1)\n• Depth of focus (1)\n• Distance from epicentre (1)\n• Population density (1)\n• Level of preparedness (1)\n• Quality of building construction (1) (any three)' },
      { q: 'State two characteristics of a tropical cyclone.', marks: 2, markScheme: '• Intense low-pressure weather system (1)\n• Sustained wind speeds of 119 km/h or greater (1)\n• Eye at the centre surrounded by eyewall (1)\n• Formed over warm tropical oceans (1) (any two)' },
      { q: 'Define the term "tectonic hazard".', marks: 2, markScheme: '• A hazard/threat to people and property (1)\n• Caused by geological processes such as earthquakes and volcanic eruptions (1)' },
      { q: 'State two reasons why people continue to live in hazardous areas.', marks: 2, markScheme: '• Fertile volcanic soils for agriculture (1)\n• Lack of financial resources to relocate (1)\n• Hazard events may be infrequent (1)\n• Cultural/family ties to the area (1)\n• Economic opportunities e.g. tourism, geothermal energy (1) (any two)' },
      { q: 'State two conditions required for the formation of a tropical cyclone.', marks: 2, markScheme: '• Sea surface temperature of 27°C or above (1)\n• Location at least 5° from the equator (for Coriolis effect) (1)\n• Deep layer of warm water (at least 60m) (1)\n• Atmospheric instability (1) (any two)' },
      { q: 'State the difference between the epicentre and focus of an earthquake.', marks: 2, markScheme: '• Focus is the point within the earth\'s crust where the earthquake originates/where rocks fracture (1)\n• Epicentre is the point on the earth\'s surface directly above the focus (1)' },
      { q: 'Define the term "disaster risk reduction".', marks: 3, markScheme: '• A systematic approach to identifying, assessing and reducing risk (1)\n• Of disaster/losses from natural hazards (1)\n• Through prevention, mitigation, preparedness and response strategies (1)' },

      // 4-6 mark questions (15)
      { q: 'Describe the global distribution of earthquakes and explain why they occur in these locations.', marks: 6, diagram: true, markScheme: '• Earthquakes concentrated along plate boundaries (1)\n• Particularly around the Pacific Ring of Fire (1)\n• Along mid-ocean ridges e.g. Mid-Atlantic Ridge (1)\n• At convergent boundaries: subduction creates friction and pressure (1)\n• At divergent boundaries: rifting and magma movement cause earthquakes (1)\n• At transform/conservative boundaries: plates sliding past each other cause friction (1)\n• Some intraplate earthquakes occur away from boundaries e.g. hotspots (1)\n• Credit annotated map/diagram of global distribution (max 6)' },
      { q: 'Explain how a tsunami is generated by an earthquake.', marks: 4, markScheme: '• Earthquake occurs at a subduction zone/on the ocean floor (1)\n• Vertical displacement of the sea floor displaces a large volume of water (1)\n• Energy transferred through the water as a series of waves (1)\n• Waves travel at high speed in deep water but with low height (1)\n• As waves approach shallow coastal water, they slow down and increase in height dramatically (1) (max 4)' },
      { q: 'Explain why some earthquakes cause more damage and deaths than others.', marks: 6, markScheme: '• Magnitude: higher magnitude releases more energy causing greater destruction (1)\n• Depth of focus: shallow earthquakes cause more damage at the surface (1)\n• Distance from epicentre: damage decreases with distance (1)\n• Population density: higher density means more people at risk (1)\n• Level of development: poorer countries have less resilient infrastructure (1)\n• Preparedness: early warning systems and education reduce casualties (1)\n• Building standards: earthquake-resistant buildings save lives (1)\n• Secondary hazards: fires, landslides, tsunamis add to impact (1)\n• Time of day: daytime vs nighttime affects casualties (1) (max 6)' },
      { q: 'Explain the structure of a tropical cyclone.', marks: 5, diagram: true, markScheme: '• Eye at the centre: calm, clear, sinking air, low pressure (1)\n• Eyewall: most intense winds and heaviest rainfall (1)\n• Spiral rainbands extending outwards from the eyewall (1)\n• Warm moist air rises rapidly around the eye (1)\n• Air spirals inward at low levels, outward at high levels (1)\n• Credit annotated cross-section diagram' },
      { q: 'Explain two ways in which volcanic eruptions can affect the global climate.', marks: 4, markScheme: '• Large eruptions inject sulphur dioxide (SO2) into the stratosphere (1)\n• SO2 forms sulphate aerosols which reflect solar radiation back to space, causing global cooling (1)\n• Example: Mount Pinatubo 1991 caused ~0.5°C global cooling for 1-2 years (1)\n• Ash particles can also reduce solar radiation reaching the surface (1)\n• CO2 emissions from volcanoes contribute to long-term greenhouse effect (very small compared to human emissions) (1) (max 4)' },
      { q: 'Describe the characteristics and hazards of a pyroclastic flow.', marks: 4, markScheme: '• Fast-moving current of hot gas, ash and rock fragments (1)\n• Can reach speeds of 700 km/h and temperatures over 700°C (1)\n• Travel down the sides of the volcano following valleys (1)\n• Destroys everything in their path and are virtually impossible to outrun (1)\n• Major cause of death in volcanic eruptions e.g. Mount St Helens, Montserrat (1) (max 4)' },
      { q: 'Explain the process of convection in the Earth\'s mantle and its role in plate movement.', marks: 5, markScheme: '• Radioactive decay in the core generates heat (1)\n• Heat causes mantle rock to become less dense and rise towards the surface (1)\n• At the surface, material moves laterally, dragging plates with it (1)\n• Cooled material sinks back down, creating a convection cell (1)\n• This circular motion provides the driving force for plate tectonic movement (1)\n• Ridge push and slab pull also contribute to plate movement (1) (max 5)' },
      { q: 'Explain how building design can reduce the impacts of earthquakes.', marks: 6, markScheme: '• Deep foundations anchored to bedrock reduce shaking effects (1)\n• Steel-framed structures flex rather than collapse (1)\n• Base isolation: rubber/spring mounts absorb seismic energy (1)\n• Cross-bracing and shear walls resist lateral forces (1)\n• Lightweight roof materials reduce collapse injuries (1)\n• Fire-resistant materials prevent secondary fire hazard (1)\n• Regular spacing between buildings prevents domino collapse effect (1) (max 6)' },
      { q: 'Explain why tropical cyclones weaken after making landfall.', marks: 4, markScheme: '• Cut off from warm ocean water which provides energy through evaporation (1)\n• Increased friction from land surface slows wind speeds (1)\n• Loss of moisture supply reduces rainfall intensity (1)\n• The cyclone\'s energy source (latent heat from condensation) is reduced (1)\n• May break up over mountainous terrain (1) (max 4)' },
      { q: 'Explain the role of the Coriolis effect in the formation and movement of tropical cyclones.', marks: 4, markScheme: '• Coriolis effect is the deflection of moving air/water due to Earth\'s rotation (1)\n• Causes air flowing towards the low-pressure centre to spiral rather than flow directly inward (1)\n• Creates the characteristic rotation of the cyclone (anticlockwise in Northern Hemisphere, clockwise in Southern) (1)\n• Cyclones cannot form within 5° of equator because Coriolis effect is too weak (1)\n• Also influences the track/path of cyclones as they move poleward (1) (max 4)' },
      { q: 'Explain two differences in the impacts of hazards between high-income and low-income countries.', marks: 6, markScheme: '• Death toll: LICs typically suffer higher death tolls due to weaker infrastructure and emergency services (1)\n• Developed point: e.g. Haiti 2010 earthquake killed ~220,000 vs Christchurch 2011 killed 185 despite similar magnitude (1)\n• Economic cost: HICs suffer higher absolute economic losses due to value of property and infrastructure (1)\n• Developed point: but can afford recovery; LICs suffer greater proportional GDP loss (1)\n• Recovery time: HICs recover faster due to insurance, aid capacity, and governance (1)\n• Developed point: LICs may take decades to recover and development gains are set back (1)' },
      { q: 'Describe the hazards associated with tropical cyclones.', marks: 5, markScheme: '• Extreme winds: sustained winds >119 km/h cause structural damage (1)\n• Storm surge: rise in sea level pushing seawater inland, major cause of flooding and death (1)\n• Intense rainfall: causes river flooding and landslides (1)\n• Coastal flooding from combined storm surge and high waves (1)\n• Tornadoes: can be spawned within the outer bands of the cyclone (1)' },
      { q: 'Explain how monitoring and prediction can reduce the impacts of volcanic eruptions.', marks: 5, markScheme: '• Seismometers detect increased earthquake activity indicating magma movement (1)\n• Ground deformation measured by GPS and tiltmeters shows swelling (1)\n• Gas emissions: increased SO2 suggests rising magma (1)\n• Satellite remote sensing monitors thermal changes and ground deformation (1)\n• Predictions allow evacuation of at-risk areas, saving lives (1)\n• Limitations: not all volcanoes are monitored; predictions not always accurate (1) (max 5)' },
      { q: 'Explain how El Nino events can increase the risk of natural hazards.', marks: 6, markScheme: '• El Nino involves warming of eastern Pacific Ocean surface waters (1)\n• Disrupts normal atmospheric circulation patterns globally (1)\n• Increases drought risk in Australia, Southeast Asia, and parts of Africa (1)\n• Increases heavy rainfall and flooding in western South America (1)\n• Can increase tropical cyclone activity in the Pacific (1)\n• Drought conditions increase wildfire risk (1)\n• Coral bleaching from warmer sea temperatures (1) (max 6)' },
      { q: 'Explain why the impacts of earthquakes are often greater in low-income countries.', marks: 5, markScheme: '• Weaker building standards mean structures collapse more easily (1)\n• Limited emergency services and equipment for search and rescue (1)\n• Poorer healthcare infrastructure means injuries become fatalities (1)\n• Higher population density in vulnerable housing (1)\n• Less financial resources for preparedness, mitigation and recovery (1)\n• Weaker governance may mean poor enforcement of building codes (1) (max 5)' },

      // 8-9 mark questions (10)
      { q: 'Explain how plate tectonic theory helps us understand the distribution and nature of tectonic hazards.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation linking plate tectonics to hazard distribution and characteristics. Accurate terminology and examples.\nLevel 2 (4-6 marks): Some links between plate tectonics and hazards with partial development.\nLevel 1 (1-3 marks): Basic description of plate tectonics or hazards.\n\nIndicative content:\n• Convergent boundaries: subduction causes deep earthquakes and explosive volcanism\n• Divergent boundaries: shallow earthquakes and effusive volcanism\n• Conservative boundaries: earthquakes only (no volcanism)\n• Hotspots: volcanic activity away from plate boundaries\n• Pacific Ring of Fire: most active zone\n• Type of plate boundary determines hazard characteristics\n• Explains why some areas are multi-hazard zones\n• Intraplate hazards as exceptions to the pattern\n• Named examples for each boundary type' },
      { q: 'Explain how and why the impacts of tropical cyclones vary between different countries. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation with multiple factors and well-developed examples. Clear comparison between countries.\nLevel 2 (4-6 marks): Some factors and examples with partial comparison.\nLevel 1 (1-3 marks): Basic description of cyclone impacts.\n\nIndicative content:\n• Level of economic development affects infrastructure resilience\n• Warning systems: HICs have better forecasting and communication\n• Evacuation capabilities and transport infrastructure\n• Building standards and enforcement\n• Emergency response capacity\n• Insurance and financial recovery\n• Population vulnerability (poverty, health, age structure)\n• Physical factors: coastal topography, cyclone intensity\n• Named examples: e.g. Hurricane Katrina (USA) vs Cyclone Nargis (Myanmar)' },
      { q: 'Assess the effectiveness of different strategies used to manage earthquake hazards.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed assessment of multiple strategies with clear evaluation of effectiveness. Well-supported by examples.\nLevel 2 (4-6 marks): Some strategies assessed with partial evaluation.\nLevel 1 (1-3 marks): Basic description of strategies.\n\nIndicative content:\nPrediction and monitoring:\n• Seismic monitoring, GPS ground deformation\n• Currently cannot predict earthquakes reliably\nProtection:\n• Earthquake-resistant building design\n• Retrofitting older buildings\n• Land-use planning and zoning\nPreparedness:\n• Education and drills\n• Emergency supplies and plans\n• Early warning systems (limited seconds)\nResponse:\n• Search and rescue capabilities\n• International aid coordination\nEffectiveness varies with:\n• Level of development/resources\n• Governance and enforcement\n• Named examples of success and failure' },
      { q: 'Explain how climate change may alter the global distribution and intensity of weather-related hazards.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple hazard types with clear links to climate change. Uses evidence.\nLevel 2 (4-6 marks): Some links between climate change and hazards.\nLevel 1 (1-3 marks): Basic identification of climate change effects.\n\nIndicative content:\n• Tropical cyclones: warmer oceans may increase intensity, possible poleward shift\n• Sea level rise increases storm surge flooding risk\n• More extreme precipitation events increase flood risk\n• Increased drought frequency and severity in some regions\n• Wildfire risk increases with higher temperatures and drought\n• Heatwaves become more frequent and intense\n• Shifting of climate zones and associated hazards\n• Uncertainty in predictions\n• Some areas may face new hazards they have not experienced before' },
      { q: 'Explain how a named volcanic eruption impacted people and the environment. Assess the effectiveness of the response.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed case study knowledge with thorough assessment of response effectiveness.\nLevel 2 (4-6 marks): Some case study knowledge with partial assessment.\nLevel 1 (1-3 marks): Basic description of impacts.\n\nIndicative content (e.g. Montserrat 1997 or other valid example):\nImpacts:\n• Deaths and injuries\n• Destruction of settlements and infrastructure\n• Agricultural land buried\n• Environmental damage\n• Population displacement\n• Economic losses\nResponse:\n• Evacuation procedures\n• Exclusion zones established\n• International aid\n• Monitoring programmes\n• Relocation assistance\nAssessment:\n• What worked well and what did not\n• Short-term vs long-term effectiveness\n• Lessons learned for future events' },
      { q: 'Explain the factors that influence the severity of impacts from natural hazards and how they interact.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple interacting factors. Clear understanding of how factors combine to influence severity.\nLevel 2 (4-6 marks): Several factors identified with some interaction discussed.\nLevel 1 (1-3 marks): Basic listing of factors.\n\nIndicative content:\n• Physical factors: magnitude, duration, frequency, speed of onset\n• Vulnerability: poverty, population density, age structure, health\n• Exposure: proximity to hazard, land use in hazardous areas\n• Capacity: governance, infrastructure, technology, education\n• Resilience: economic resources, social capital, insurance\n• Interaction: high magnitude + high vulnerability = catastrophe\n• Low magnitude + high capacity = minor event\n• Multiple hazards can compound effects\n• Pre-existing conditions (conflict, poverty) worsen impacts' },
      { q: 'Explain how understanding of atmospheric circulation helps predict the tracks and impacts of tropical cyclones.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation linking atmospheric circulation to cyclone behaviour. Accurate and well-developed.\nLevel 2 (4-6 marks): Some links between circulation and cyclone tracks.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Trade winds steer cyclones westward in the tropics\n• Coriolis effect causes poleward curvature\n• Jet streams can influence track at higher latitudes\n• ITCZ position determines formation zone seasonally\n• ENSO affects steering currents and formation regions\n• High-pressure systems can block or redirect cyclones\n• Upper-level wind shear can weaken cyclones\n• Satellite and weather balloon data track atmospheric conditions\n• Computer models use circulation data to forecast tracks\n• Accuracy improves but still uncertainty 3-5 days ahead' },
      { q: 'Explain the concept of the hazard management cycle and assess how it can reduce disaster impacts.', marks: 9, markScheme: 'Level 3 (7-9 marks): Clear explanation of all stages with assessment of how each reduces impacts. Well-exemplified.\nLevel 2 (4-6 marks): Some stages explained with partial assessment.\nLevel 1 (1-3 marks): Basic description of one or two stages.\n\nIndicative content:\nMitigation:\n• Actions to reduce risk before event e.g. building codes, land zoning\n• Long-term investment reduces future losses\nPreparedness:\n• Planning, training, drills, stockpiling supplies\n• Warning systems and communication plans\nResponse:\n• Immediate actions during/after event: rescue, emergency shelter, medical care\n• Effectiveness depends on preparedness\nRecovery:\n• Short-term: restore essential services\n• Long-term: rebuild, "build back better"\nAssessment:\n• Continuous cycle, each stage strengthens others\n• Most effective when all stages adequately resourced\n• LICs may lack resources for all stages\n• Examples of successful implementation' },
      { q: 'Explain how the characteristics of different types of plate boundary create different types of volcanic hazard.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation linking boundary types to volcanic characteristics. Accurate use of terminology.\nLevel 2 (4-6 marks): Some links between boundaries and volcanic types.\nLevel 1 (1-3 marks): Basic description of volcanism.\n\nIndicative content:\nConvergent (destructive):\n• Subducting plate melts, generating viscous, gas-rich magma\n• Explosive eruptions: pyroclastic flows, ash, lahars\n• Composite/stratovolcanoes e.g. Mount St Helens\nDivergent (constructive):\n• Basaltic magma rises through gap between plates\n• Effusive eruptions: lava flows, shield volcanoes\n• Less explosive due to low silica, low gas content\n• E.g. Iceland, mid-ocean ridges\nHotspots:\n• Mantle plume creates volcanic activity away from boundaries\n• Can produce both effusive and explosive eruptions\n• E.g. Hawaii (shield), Yellowstone (supervolcano)\n• Magma composition determines hazard type' },
      { q: 'Explain how disaster risk can be reduced through international cooperation and governance. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation with multiple examples of international cooperation. Clear links to risk reduction.\nLevel 2 (4-6 marks): Some examples with partial explanation.\nLevel 1 (1-3 marks): Basic identification of international efforts.\n\nIndicative content:\n• Sendai Framework for Disaster Risk Reduction 2015-2030\n• International early warning systems (e.g. Indian Ocean Tsunami Warning System)\n• UN OCHA coordination of humanitarian response\n• Financial mechanisms: insurance, World Bank funding\n• Technology transfer and capacity building\n• Sharing of scientific data and monitoring resources\n• International search and rescue teams\n• NGO networks for preparedness and response\n• Challenges: national sovereignty, political will, funding\n• Examples of successful cooperation e.g. Pacific tsunami warning' },

      // 12-20 mark questions (5)
      { q: '"The severity of natural hazards is determined more by human factors than physical factors." To what extent do you agree? Use examples.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough and balanced evaluation of both human and physical factors with clear judgement. Well-supported by contrasting examples.\nLevel 3 (9-12 marks): Good discussion of both factors with some balance.\nLevel 2 (5-8 marks): Some relevant points but limited balance.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nHuman factors:\n• Level of economic development and infrastructure quality\n• Population density and vulnerability\n• Governance, planning and preparedness\n• Land use decisions in hazardous areas\n• Climate change increasing hazard frequency/intensity\nPhysical factors:\n• Magnitude and intensity of the event\n• Depth, location, duration\n• Secondary hazards (tsunamis, landslides)\n• Speed of onset and frequency\nExamples comparing:\n• Haiti 2010 vs Chile 2010 (similar earthquakes, different impacts)\n• Hurricane Katrina vs other cyclone events\n• Judgement: are human factors more important?\n• Context-dependent answer: both matter but human factors often determine severity of impact' },
      { q: 'Evaluate the extent to which prediction and monitoring can reduce the impacts of tectonic hazards. Refer to examples.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation of prediction/monitoring for both earthquakes and volcanoes. Clear judgement supported by examples.\nLevel 3 (9-12 marks): Good evaluation with some comparison between hazard types.\nLevel 2 (5-8 marks): Describes monitoring methods with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nVolcanoes:\n• Seismic monitoring, gas emissions, ground deformation\n• Generally more predictable than earthquakes\n• Successful evacuations: e.g. Mount Pinatubo 1991\n• Failures: unpredicted eruptions still occur\nEarthquakes:\n• Cannot be reliably predicted\n• Seismic gap theory, animal behaviour - unreliable\n• Early warning systems provide seconds of warning\n• Focus on preparedness rather than prediction\nEvaluation:\n• Prediction more effective for volcanoes than earthquakes\n• Monitoring reduces impact only if linked to action (evacuation)\n• Cost and coverage issues in LICs\n• Preparedness may be more effective overall\n• Technology improving but limitations remain' },
      { q: 'Assess the extent to which different factors influence the risk posed by tropical cyclones. Use examples.', marks: 12, markScheme: 'Level 4 (10-12 marks): Thorough assessment of multiple factors with clear judgement of relative importance. Well-exemplified.\nLevel 3 (7-9 marks): Good range of factors assessed with examples.\nLevel 2 (4-6 marks): Describes factors with limited assessment.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nPhysical factors:\n• Cyclone intensity (Saffir-Simpson scale)\n• Storm surge height and coastal topography\n• Rainfall intensity and duration\n• Track and speed of movement\nHuman factors:\n• Population density of affected coastlines\n• Level of economic development\n• Warning systems and evacuation infrastructure\n• Coastal development and urbanisation\n• Climate change: warming oceans potentially intensifying cyclones\nExamples:\n• Typhoon Haiyan (Philippines 2013)\n• Hurricane Harvey (USA 2017)\n• Assessment of which factors most influence risk' },
      { q: 'Discuss the view that people in hazardous areas should be responsible for their own safety rather than relying on government support. Use examples.', marks: 20, markScheme: 'Level 5 (17-20 marks): Sophisticated, balanced discussion with well-developed arguments on both sides. Sustained evaluation with clear judgement. Excellent use of examples.\nLevel 4 (13-16 marks): Detailed discussion with good balance and examples.\nLevel 3 (9-12 marks): Some discussion with partial balance.\nLevel 2 (5-8 marks): Limited discussion with few examples.\nLevel 1 (1-4 marks): Basic points with minimal discussion.\n\nIndicative content:\nIndividual responsibility:\n• Personal preparedness (emergency kits, plans)\n• Building choices and insurance\n• Choice to live in hazardous areas\n• Community-level resilience and mutual aid\n• Indigenous knowledge and local adaptation\nGovernment responsibility:\n• Building regulations and enforcement\n• Warning systems and evacuation infrastructure\n• Emergency services and disaster response\n• Land-use planning and zoning\n• International cooperation\n• Duty to protect citizens especially vulnerable groups\nDiscussion:\n• Inequality: poorest often have no choice but to live in risky areas\n• Scale of disasters often beyond individual capability\n• Balance between individual and collective responsibility\n• Different models: Japan (shared), USA (more individual), Bangladesh (community)\n• Government failure examples vs community success stories' },
      { q: '"Climate change is the greatest threat to global hazard risk in the 21st century." Evaluate this statement with reference to evidence.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation considering climate change alongside other factors affecting hazard risk. Evidence-based judgement.\nLevel 3 (9-12 marks): Good discussion with some evaluation and evidence.\nLevel 2 (5-8 marks): Some relevant points with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nClimate change as a threat:\n• More intense tropical cyclones from warmer oceans\n• Sea level rise increasing storm surge flooding\n• More frequent extreme weather events\n• Drought, wildfire, and heatwave risk increasing\n• Melting permafrost destabilising slopes\nOther threats:\n• Urbanisation in hazardous areas\n• Population growth increasing exposure\n• Poverty and inequality maintaining vulnerability\n• Political instability reducing governance capacity\n• Environmental degradation (deforestation, wetland loss)\nEvaluation:\n• Climate change amplifies many existing hazards\n• But human vulnerability factors often determine impact severity\n• Tectonic hazards not directly linked to climate change\n• Multiple interacting threats rather than single greatest one\n• Geographical variation in which threat is most significant' },
    ],
  },

  '2.1': {
    name: 'Changing Spaces, Making Places',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two ways in which a place can be represented.', marks: 2, markScheme: '• Through maps/cartography (1)\n• Through photographs/art/paintings (1)\n• Through written accounts/literature (1)\n• Through film/media (1)\n• Through music/poetry (1)\n• Through statistics/census data (1) (any two)' },
      { q: 'Define the term "sense of place".', marks: 2, markScheme: '• The subjective emotional attachment/feeling (1)\n• That people have towards a particular place based on their experiences and perceptions (1)' },
      { q: 'State two factors that influence a person\'s perception of a place.', marks: 2, markScheme: '• Age (1)\n• Gender (1)\n• Ethnicity (1)\n• Socioeconomic status (1)\n• Length of residence (1)\n• Personal experience/memories (1)\n• Media representation (1) (any two)' },
      { q: 'Define the term "place identity".', marks: 2, markScheme: '• The characteristics and qualities of a place (1)\n• That distinguish it from other places and give it a unique character (1)' },
      { q: 'State two economic characteristics that can be used to compare places.', marks: 2, markScheme: '• Employment structure/types of jobs (1)\n• Average income/wages (1)\n• House prices (1)\n• Business types and number (1)\n• Unemployment rate (1) (any two)' },
      { q: 'State two ways in which globalisation has changed the character of places.', marks: 2, markScheme: '• Introduction of global brands/chain stores replacing independent businesses (1)\n• Increased cultural diversity through migration (1)\n• Standardisation of architecture and urban design (1)\n• Changes to local employment structure e.g. deindustrialisation (1) (any two)' },
      { q: 'Define the term "lived experience" of a place.', marks: 3, markScheme: '• The everyday personal encounters and interactions (1)\n• That individuals have with a place (1)\n• Shaped by their social, cultural and economic circumstances (1)' },
      { q: 'State two demographic characteristics of a place.', marks: 2, markScheme: '• Population size/density (1)\n• Age structure (1)\n• Ethnic composition (1)\n• Migration rates (1)\n• Birth/death rates (1) (any two)' },
      { q: 'State two ways in which past processes shape the present character of places.', marks: 2, markScheme: '• Industrial heritage e.g. old factories/mills influence current land use (1)\n• Historical migration patterns shape current ethnic diversity (1)\n• Past planning decisions e.g. council housing estates (1)\n• Historical economic base shapes current employment opportunities (1) (any two)' },
      { q: 'Define the term "gentrification".', marks: 3, markScheme: '• The process by which an area is changed (1)\n• By wealthier people moving in, renovating properties (1)\n• Often displacing original lower-income residents and changing the character of the area (1)' },

      // 4-6 mark questions (15)
      { q: 'Explain how different people may have contrasting perceptions of the same place.', marks: 6, markScheme: '• Age: young people may see a place as boring while elderly value its quietness (1)\n• Length of residence: long-term residents may feel nostalgia while newcomers see decline (1)\n• Socioeconomic status: wealthy residents may see an area positively while poorer residents feel excluded (1)\n• Ethnicity/culture: different cultural groups may value different aspects of a place (1)\n• Role: residents vs visitors vs workers have different experiences (1)\n• Media representation can shape perceptions for those who have not visited (1)' },
      { q: 'Explain how economic change can alter the character of a place. Use an example.', marks: 6, markScheme: '• Deindustrialisation can lead to job losses and deprivation (1)\n• Decline in traditional industries changes employment structure (1)\n• Physical environment changes: derelict buildings, brownfield sites (1)\n• Social changes: outmigration of working-age population, ageing population (1)\n• Or: new investment/regeneration brings new jobs and residents (1)\n• Named example with specific detail of economic change and its effects (1)' },
      { q: 'Explain two ways in which media representations can influence people\'s perceptions of a place.', marks: 4, markScheme: '• Positive media: tourism advertising, TV shows set in attractive locations create aspirational image (1)\n• Developed explanation: attracts visitors and investment, raises property values (1)\n• Negative media: crime reporting, deprivation statistics create stigmatised image (1)\n• Developed explanation: deters investment, reinforces inequality, can become self-fulfilling (1)' },
      { q: 'Explain how migration has changed the character of a named place.', marks: 6, markScheme: '• Named place with relevant detail (1)\n• Demographic change: increased ethnic and cultural diversity (1)\n• Cultural landscape: new places of worship, restaurants, shops (1)\n• Social changes: community organisations, cultural festivals (1)\n• Economic impacts: new businesses, labour force changes (1)\n• Potential tensions: pressure on services, cultural friction (1)\n• Overall transformation of place identity and character (1) (max 6)' },
      { q: 'Explain how the built environment of a place reflects its history.', marks: 5, markScheme: '• Architecture styles reflect different periods of construction (1)\n• Industrial buildings indicate former economic activities e.g. mills, warehouses (1)\n• Religious buildings reflect historical communities and beliefs (1)\n• Street patterns may reflect medieval, Georgian, or Victorian planning (1)\n• Monuments and memorials commemorate historical events and people (1)\n• Housing types reflect social conditions of different eras e.g. back-to-back terraces (1) (max 5)' },
      { q: 'Explain how gentrification changes the social and economic character of a place.', marks: 6, markScheme: '• Wealthier residents move in, increasing average income levels (1)\n• Property prices and rents increase significantly (1)\n• Original lower-income residents may be priced out and displaced (1)\n• Independent shops replaced by upmarket boutiques, cafes, galleries (1)\n• Physical environment improves through renovation and investment (1)\n• Community character changes: new social networks replace established ones (1)\n• Can create social tension between old and new residents (1) (max 6)' },
      { q: 'Explain how government policy can shape the character of a place. Use an example.', marks: 6, markScheme: '• Planning decisions determine land use and development types (1)\n• Housing policy: council housing, right-to-buy, affordable housing requirements (1)\n• Regeneration initiatives target specific areas for investment (1)\n• Transport infrastructure connects or isolates places (1)\n• Enterprise zones and tax incentives attract businesses (1)\n• Named example with specific policy and its effects on place character (1)' },
      { q: 'Explain how quantitative and qualitative data can be used to investigate the character of a place.', marks: 6, markScheme: '• Quantitative: census data provides demographic and economic statistics (1)\n• Population density, age structure, ethnicity breakdown, employment data (1)\n• IMD (Index of Multiple Deprivation) ranks areas by deprivation (1)\n• Qualitative: interviews and questionnaires capture personal experiences (1)\n• Photographs and sketches record visual character and land use (1)\n• Analysis of media representations, literature, art about the place (1)\n• Combination provides both measurable facts and subjective meanings (1) (max 6)' },
      { q: 'Explain how globalisation creates "placelessness".', marks: 4, markScheme: '• Global brands and chain stores create identical high streets everywhere (1)\n• Same architecture and building styles replicated in different countries (1)\n• Loss of local distinctiveness and unique character (1)\n• Cultural homogenisation through global media and consumer culture (1)\n• Example: shopping centres, airports, business districts look similar worldwide (1) (max 4)' },
      { q: 'Explain how the concept of "insider" and "outsider" perspectives helps understand a place.', marks: 5, markScheme: '• Insiders are people who live in and have personal experience of a place (1)\n• They have deep knowledge and emotional attachment based on daily experience (1)\n• Outsiders observe and interpret a place without this lived experience (1)\n• Outsiders may rely on media representations or brief visits (1)\n• Different perspectives can lead to contrasting understandings of the same place (1)\n• Both perspectives are valid but may be partial or biased (1) (max 5)' },
      { q: 'Explain how a place profile can be used to understand the character of a place.', marks: 5, markScheme: '• A place profile combines demographic, economic and social data (1)\n• Includes quantitative data: population, employment, income, housing (1)\n• Includes qualitative data: perceptions, lived experiences, representations (1)\n• Physical characteristics: location, land use, built environment (1)\n• Allows comparison with other places and identification of change over time (1)\n• Helps understand the factors that have shaped the place (1) (max 5)' },
      { q: 'Explain how the decline of traditional industries has affected communities in the UK. Use an example.', marks: 6, markScheme: '• Loss of major employer leads to high unemployment (1)\n• Skills mismatch: workers trained for industry not suited to new service jobs (1)\n• Outmigration of young working-age people seeking employment (1)\n• Physical decline: derelict industrial buildings, run-down housing (1)\n• Social problems: poverty, poor health, low aspirations (1)\n• Named example e.g. former mining/steel/shipbuilding communities with specific detail (1)' },
      { q: 'Explain how rural places in the UK have been affected by counterurbanisation.', marks: 5, markScheme: '• Wealthier urban residents move to rural areas seeking quality of life (1)\n• House prices increase, making housing unaffordable for local people (1)\n• Demand for services changes: some local shops close, replaced by commuter needs (1)\n• Village character changes: dormitory villages, second homes (1)\n• Social tensions between newcomers and established residents (1)\n• Can bring some economic benefits: investment, new businesses (1) (max 5)' },
      { q: 'Explain two ways in which place identity can be contested.', marks: 4, markScheme: '• Different groups may disagree about the heritage/history that defines a place (1)\n• E.g. debate over statues/monuments representing contested histories (1)\n• Development vs conservation: disagreement about whether change is positive (1)\n• E.g. new housing development on greenfield site opposed by existing residents (1)' },
      { q: 'Explain how transport infrastructure influences the character and connectivity of places.', marks: 5, markScheme: '• Motorways/railways connect places to wider economic networks (1)\n• Well-connected places attract investment and commuters (1)\n• Poorly connected places may experience economic decline and isolation (1)\n• HS2/Crossrail type projects aim to rebalance regional economies (1)\n• Transport hubs create distinctive place characteristics e.g. station towns (1)\n• Can also bring negative impacts: noise, pollution, severance of communities (1) (max 5)' },

      // 8-9 mark questions (10)
      { q: 'Explain how and why the character of places changes over time. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple drivers of change with well-developed examples. Clear understanding of interconnected processes.\nLevel 2 (4-6 marks): Some drivers of change discussed with examples.\nLevel 1 (1-3 marks): Basic description of change.\n\nIndicative content:\n• Economic restructuring: deindustrialisation to service economy\n• Demographic change: migration, ageing, population growth/decline\n• Globalisation: cultural change, new businesses, placelessness\n• Government policy: regeneration, planning decisions\n• Technological change: impact on employment, connectivity\n• Social change: gentrification, changing lifestyles\n• Environmental change: climate adaptation\n• Named examples showing specific changes and their effects' },
      { q: 'Explain how different stakeholders may have conflicting views about the regeneration of a place. Use a named example.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple stakeholder perspectives with clear conflicts. Well-developed named example.\nLevel 2 (4-6 marks): Some stakeholder views with partial conflict identification.\nLevel 1 (1-3 marks): Basic description of regeneration.\n\nIndicative content:\n• Local residents: may welcome improvement but fear displacement/rising costs\n• Developers: profit motive, want maximum development density\n• Local authority: balance economic growth with community needs\n• Businesses: existing may fear competition, new ones attracted by investment\n• Environmental groups: may oppose development on green spaces\n• Heritage groups: want to preserve historical character\n• Young people vs older residents: different visions for the area\n• Named example with specific stakeholder conflicts' },
      { q: 'Assess the importance of past and present connections in shaping the identity of places.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed assessment of both past and present connections with clear judgement. Well-exemplified.\nLevel 2 (4-6 marks): Some assessment with partial examples.\nLevel 1 (1-3 marks): Basic description of connections.\n\nIndicative content:\nPast connections:\n• Colonial trade links shaping port cities\n• Industrial revolution creating factory towns\n• Historical migration creating diverse communities\n• Military/political history shaping national identity\nPresent connections:\n• Global economic networks and TNCs\n• Modern migration flows\n• Digital connectivity and social media\n• Transport links and commuting patterns\n• Cultural exchanges and tourism\nAssessment:\n• How past shapes present identity\n• Whether present connections are overriding historical identity\n• Place-specific examples' },
      { q: 'Explain how inequality within places can be measured and why it is significant.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of measurement methods and clear analysis of significance. Well-developed.\nLevel 2 (4-6 marks): Some methods and significance discussed.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nMeasurement:\n• Index of Multiple Deprivation (IMD): income, employment, health, education, crime, environment, housing\n• Census data: demographics, housing tenure, qualifications\n• Income and house price data\n• Health statistics: life expectancy, obesity rates\n• Educational attainment data\nSignificance:\n• Reveals spatial patterns of advantage/disadvantage\n• Highlights need for targeted intervention\n• Affects life chances and social mobility\n• Can be self-reinforcing through cycles of deprivation\n• Political implications for resource allocation\n• Named examples of inequality within places' },
      { q: 'Explain how the concept of "place" is more than just a location. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Sophisticated understanding of place as a concept beyond location. Clear theoretical framework with examples.\nLevel 2 (4-6 marks): Some understanding of broader concept with partial examples.\nLevel 1 (1-3 marks): Basic distinction between place and location.\n\nIndicative content:\n• Location: fixed coordinates, objective, measurable\n• Place involves meaning, identity, and human attachment\n• Sense of place: emotional connection and belonging\n• Place as socially constructed: different groups create different meanings\n• Insider vs outsider perspectives\n• Places shaped by history, culture, economy\n• Representations in media create place images\n• Places change through time but retain identity elements\n• Examples: how a hometown means different things to different people' },
      { q: 'Explain how urban regeneration schemes aim to change the character of places. Use a named example.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of regeneration aims and methods with thorough named example. Clear understanding of how character changes.\nLevel 2 (4-6 marks): Some explanation with partial example.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Physical regeneration: demolishing derelict buildings, new housing, improved public spaces\n• Economic regeneration: attracting investment, creating jobs, new businesses\n• Social regeneration: community facilities, education, health improvements\n• Environmental improvements: green spaces, sustainable design\n• Cultural regeneration: arts, heritage, creative industries\n• Named example (e.g. London Docklands, Salford Quays, Liverpool ONE) with specific details\n• Assessment of success: who benefits, who loses\n• Short-term vs long-term changes to place character' },
      { q: 'Explain how fieldwork techniques can be used to investigate how people perceive a place differently.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple techniques with clear methodology. Understands how data reveals perceptions.\nLevel 2 (4-6 marks): Some techniques described with partial methodology.\nLevel 1 (1-3 marks): Basic listing of techniques.\n\nIndicative content:\n• Questionnaires: structured questions about attitudes, feelings, experiences\n• Interviews: semi-structured to explore personal perceptions in depth\n• Mental maps: ask respondents to draw their perception of the area\n• Photography: participants photograph what they consider important/representative\n• Environmental quality surveys: rate different aspects of the place\n• Bi-polar analysis: rate characteristics on a scale\n• Sampling strategy: ensure different demographic groups represented\n• Ethical considerations: informed consent, anonymity\n• Analysis: comparison between groups (age, gender, resident/visitor)' },
      { q: 'Explain how external forces such as globalisation and government policy interact to shape places.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of how both forces interact with clear examples. Understands complexity of place-shaping.\nLevel 2 (4-6 marks): Some explanation of both forces with partial interaction.\nLevel 1 (1-3 marks): Basic description of one or both forces.\n\nIndicative content:\n• Globalisation brings TNCs, cultural change, migration\n• Government policy can encourage or resist globalisation effects\n• Enterprise zones attract global investment\n• Planning regulations control development\n• Immigration policy shapes demographic change\n• Trade policy affects local industries\n• Regeneration funding targets places affected by global economic change\n• Interaction: policy mediates globalisation\'s effects on places\n• Places respond differently depending on local conditions\n• Named examples of this interaction' },
      { q: 'Explain how demographic change affects the character and identity of places. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple demographic changes and their effects. Well-developed examples.\nLevel 2 (4-6 marks): Some demographic changes discussed with partial examples.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Ageing population: changing service needs, quieter communities, reduced labour force\n• Youth outmigration from rural areas: declining services, school closures\n• International migration: cultural diversity, new businesses, language changes\n• Internal migration: commuter villages, student areas\n• Population growth: pressure on housing, services, infrastructure\n• Population decline: empty properties, service withdrawal\n• Suburbanisation and counterurbanisation changing urban-rural character\n• Named examples with specific demographic data and effects' },
      { q: 'Assess the view that places are becoming increasingly similar due to globalisation.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced assessment with evidence for and against. Clear judgement with well-developed examples.\nLevel 2 (4-6 marks): Some assessment with partial evidence.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nIncreasing similarity:\n• Clone towns: same chain stores on every high street\n• Global brands dominate consumer landscape\n• Similar architecture and urban design worldwide\n• Cultural homogenisation through media\nRemaining distinctiveness:\n• Local resistance movements and cultural preservation\n• Glocalisation: global brands adapted to local contexts\n• Historical built environment maintains uniqueness\n• Natural landscape provides unique character\n• Local governance and planning controls\n• Community identity and attachment to place\nAssessment:\n• Degree of similarity varies between places\n• Surface similarity vs deeper cultural distinctiveness\n• Examples of both homogenised and distinctive places' },

      // 12-20 mark questions (5)
      { q: '"Regeneration benefits everyone in a community." Evaluate this statement with reference to a named place.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation with detailed named example. Balanced consideration of winners and losers. Clear judgement.\nLevel 3 (9-12 marks): Good evaluation with named example and some balance.\nLevel 2 (5-8 marks): Some relevant points with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nBenefits:\n• Improved physical environment and infrastructure\n• New employment opportunities\n• Better housing quality\n• Improved public services and amenities\n• Increased property values\n• Enhanced place image\nCritiques:\n• Gentrification displacing original residents\n• Rising costs of living and housing\n• New jobs may not match skills of existing residents\n• Loss of community identity and social networks\n• Benefits may flow to outsiders/developers not local people\n• Consultation may be inadequate\nNamed example with specific evidence of both benefits and drawbacks' },
      { q: 'To what extent is a person\'s experience of a place shaped by their identity? Use examples.', marks: 16, markScheme: 'Level 4 (13-16 marks): Sophisticated evaluation of how multiple aspects of identity shape place experience. Well-developed with diverse examples.\nLevel 3 (9-12 marks): Good discussion of identity and place with some evaluation.\nLevel 2 (5-8 marks): Some relevant points with limited depth.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\n• Age: young vs elderly experience places differently (safety, access, services)\n• Gender: women may feel unsafe in certain areas/times; gendered spaces\n• Ethnicity: cultural belonging, racism, cultural landscape\n• Class/income: access to services, housing quality, neighbourhood choice\n• Disability: accessibility, inclusive design\n• Sexuality: safe spaces, visibility, community areas\n• Religious identity: places of worship, cultural practices\n• Intersectionality: multiple identities interact\n• Power and exclusion: some groups\' experiences marginalised\n• Counter-argument: shared experiences transcend identity\n• Examples: how different groups experience the same place differently' },
      { q: 'Discuss the extent to which places can maintain their unique identity in an increasingly globalised world.', marks: 20, markScheme: 'Level 5 (17-20 marks): Exceptional discussion with sophisticated understanding of globalisation\'s effects on place identity. Sustained, nuanced argument.\nLevel 4 (13-16 marks): Detailed discussion with good balance and examples.\nLevel 3 (9-12 marks): Some discussion with partial balance.\nLevel 2 (5-8 marks): Limited discussion.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nThreats to unique identity:\n• Clone towns and placelessness\n• Cultural homogenisation\n• Loss of local industries and traditions\n• Migration changing demographic character\n• Global media and consumer culture\nMaintaining identity:\n• Heritage preservation and conservation areas\n• Local resistance movements\n• Place branding and marketing unique features\n• Cultural festivals and traditions\n• Planning policies protecting local character\n• Community activism and pride\n• Glocalisation as adaptation\nDiscussion:\n• Identity as fluid and evolving, not fixed\n• Global connections can strengthen local identity\n• Different scales of identity (neighbourhood, city, region)\n• Power dynamics: whose identity is preserved?\n• Role of social media in both homogenising and celebrating local identity\n• Named examples throughout' },
      { q: 'Evaluate the extent to which government policy has been successful in reducing inequality between places in the UK.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation of policies with clear evidence of success and failure. Balanced judgement.\nLevel 3 (9-12 marks): Good range of policies evaluated with some evidence.\nLevel 2 (5-8 marks): Describes policies with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nPolicies:\n• Regional development agencies and devolution\n• Enterprise zones and free ports\n• Levelling up agenda\n• Housing policy and affordable housing targets\n• Transport investment (HS2, Northern Powerhouse Rail)\n• EU structural funds (pre-Brexit)\nEvidence of success:\n• Regeneration of specific areas (e.g. Salford Quays)\n• Job creation in target areas\n• Improved infrastructure\nEvidence of failure/limitation:\n• North-south divide persists\n• London continues to dominate economically\n• Inequality within cities remains significant\n• Short-term funding cycles limit long-term impact\n• Political changes lead to policy discontinuity\n• Specific data on persistent regional inequalities' },
      { q: 'Assess the factors that create and sustain inequality within and between places. Use examples.', marks: 12, markScheme: 'Level 4 (10-12 marks): Thorough assessment of multiple factors with clear understanding of how inequality is created and sustained. Well-exemplified.\nLevel 3 (7-9 marks): Good range of factors with some assessment.\nLevel 2 (4-6 marks): Describes factors with limited assessment.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Economic factors: employment opportunities, wages, industry type\n• Historical factors: industrial legacy, colonial wealth\n• Governance: investment priorities, planning decisions\n• Social factors: education access, health provision, social capital\n• Physical factors: location, accessibility, environmental quality\n• Cycles of deprivation: poverty becomes self-reinforcing\n• Selective migration: brain drain from disadvantaged areas\n• Globalisation: uneven impacts on different places\n• Structural factors: housing market, labour market\n• Examples at different scales: within cities, between regions, between nations' },
    ],
  },

  '2.2': {
    name: 'Trade in the Contemporary World',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two benefits of international trade for developing countries.', marks: 2, markScheme: '• Access to larger markets for their goods (1)\n• Foreign exchange earnings (1)\n• Technology transfer from trading partners (1)\n• Job creation in export industries (1)\n• Economic growth and development (1) (any two)' },
      { q: 'Define the term "trade deficit".', marks: 2, markScheme: '• When the value of a country\'s imports (1)\n• Exceeds the value of its exports (1)' },
      { q: 'State two features of a free trade agreement.', marks: 2, markScheme: '• Reduction or elimination of tariffs between member countries (1)\n• Removal of quotas on traded goods (1)\n• Simplified customs procedures (1)\n• May include common regulations and standards (1) (any two)' },
      { q: 'Define the term "terms of trade".', marks: 2, markScheme: '• The ratio of export prices to import prices (1)\n• Indicates the purchasing power of a country\'s exports (1)' },
      { q: 'State two types of trade barrier.', marks: 2, markScheme: '• Tariffs (taxes on imports) (1)\n• Quotas (limits on quantity of imports) (1)\n• Subsidies to domestic producers (1)\n• Regulations/standards (non-tariff barriers) (1)\n• Embargoes (complete bans) (1) (any two)' },
      { q: 'State two ways in which trade patterns have changed in recent decades.', marks: 2, markScheme: '• Growth of South-South trade (between developing countries) (1)\n• Rise of China and other emerging economies as major trading nations (1)\n• Increase in trade in services (1)\n• Growth of global supply chains and intra-firm trade (1) (any two)' },
      { q: 'Define the term "comparative advantage".', marks: 3, markScheme: '• When a country can produce a good or service (1)\n• At a lower opportunity cost (1)\n• Than another country, even if not the cheapest absolute producer (1)' },
      { q: 'State two characteristics of a transnational corporation (TNC).', marks: 2, markScheme: '• Operates in more than one country (1)\n• Headquarters usually in a developed country (1)\n• Has global supply chains and production networks (1)\n• Large revenues often exceeding some countries\' GDP (1) (any two)' },
      { q: 'State two reasons why some countries are more dependent on primary commodity exports.', marks: 2, markScheme: '• Historical colonial economic structures focused on raw material extraction (1)\n• Lack of capital/technology for manufacturing/processing (1)\n• Abundant natural resources create comparative advantage in primary goods (1)\n• Limited infrastructure for diversified production (1) (any two)' },
      { q: 'Define the term "trade bloc".', marks: 2, markScheme: '• A group of countries that have agreed (1)\n• To reduce or eliminate trade barriers between themselves (1)' },

      // 4-6 mark questions (15)
      { q: 'Explain how trade can promote economic development in low-income countries.', marks: 6, markScheme: '• Export earnings provide foreign exchange for purchasing imports and investment (1)\n• Access to international markets creates demand for domestic products (1)\n• Competition encourages efficiency and innovation (1)\n• Technology transfer from trading partners improves productivity (1)\n• Job creation in export sectors reduces poverty (1)\n• Tax revenue from trade supports government spending on infrastructure and services (1)\n• Integration into global value chains can promote industrialisation (1) (max 6)' },
      { q: 'Explain how trade barriers can affect developing countries.', marks: 6, markScheme: '• Tariffs on exports make developing country goods more expensive in foreign markets (1)\n• Reduces competitiveness and limits market access (1)\n• Agricultural subsidies in developed countries depress global prices for primary products (1)\n• Developing country farmers cannot compete with subsidised imports (1)\n• Non-tariff barriers (standards, regulations) are costly for developing countries to meet (1)\n• Protectionism can trap countries in primary commodity dependence (1)\n• Limits foreign exchange earnings and economic diversification (1) (max 6)' },
      { q: 'Explain how the growth of global supply chains has changed patterns of trade.', marks: 6, markScheme: '• Production fragmented across multiple countries (1)\n• Components manufactured where costs are lowest (1)\n• Increased intra-firm trade within TNCs (1)\n• Growth of trade in intermediate goods, not just finished products (1)\n• Developing countries integrated as manufacturing hubs (1)\n• Value added at multiple stages across different countries (1)\n• Example: electronics supply chains across East Asia (1) (max 6)' },
      { q: 'Explain how fair trade aims to address inequalities in global trade.', marks: 5, markScheme: '• Guarantees a minimum price to producers above market price (1)\n• Provides a social premium for community development projects (1)\n• Encourages long-term trading relationships for stability (1)\n• Promotes better working conditions and environmental standards (1)\n• Empowers small-scale producers through cooperatives (1)\n• Raises consumer awareness of trade justice issues (1) (max 5)' },
      { q: 'Explain why the terms of trade for many developing countries have declined over time.', marks: 5, markScheme: '• Many developing countries export primary commodities (1)\n• Primary commodity prices are volatile and have declined relative to manufactured goods (1)\n• Oversupply of commodities depresses prices as many countries compete (1)\n• Manufactured imports have increased in price due to added value (1)\n• Countries need to export more to buy the same value of imports (1)\n• Limited bargaining power in global markets (1) (max 5)' },
      { q: 'Explain the role of the World Trade Organisation (WTO) in regulating international trade.', marks: 6, markScheme: '• Sets rules governing international trade between member nations (1)\n• Promotes free trade by negotiating reductions in trade barriers (1)\n• Provides a dispute resolution mechanism between countries (1)\n• Monitors national trade policies for compliance (1)\n• Provides technical assistance and training for developing countries (1)\n• Operates on principle of Most Favoured Nation (non-discrimination) (1)\n• Criticisms: dominated by powerful nations, slow decision-making (1) (max 6)' },
      { q: 'Explain two ways in which TNCs influence global trade patterns.', marks: 4, markScheme: '• TNCs create global supply chains sourcing materials and components from multiple countries (1)\n• This increases trade volumes and creates new trade flows between countries (1)\n• TNCs lobby governments for favourable trade policies and deregulation (1)\n• Their investment decisions determine which countries are integrated into global trade networks (1)' },
      { q: 'Explain how trade in services has grown in importance in the global economy.', marks: 5, markScheme: '• Services now account for a growing share of global trade (1)\n• Financial services, IT, telecommunications, tourism are major traded services (1)\n• Digital technology enables remote delivery of services across borders (1)\n• Outsourcing/offshoring of services to countries like India (1)\n• Service sector growth reflects shift from manufacturing in developed economies (1)\n• Developing countries increasingly competitive in service exports (1) (max 5)' },
      { q: 'Explain how membership of a trade bloc can benefit and disadvantage countries. Use an example.', marks: 6, markScheme: '• Benefit: free access to larger market increases export opportunities (1)\n• Benefit: economies of scale from serving larger market (1)\n• Benefit: increased foreign direct investment attracted by market access (1)\n• Disadvantage: competition from other members may harm domestic industries (1)\n• Disadvantage: trade diversion away from cheaper non-member suppliers (1)\n• Disadvantage: loss of sovereignty in trade policy decisions (1)\n• Named example e.g. EU, NAFTA/USMCA, ASEAN with specific detail (1) (max 6)' },
      { q: 'Explain how the pattern of trade between the UK and other countries has changed since Brexit.', marks: 5, markScheme: '• UK left EU single market and customs union (1)\n• New trade barriers with EU including customs checks and regulatory differences (1)\n• Trade with EU initially declined due to friction costs (1)\n• UK pursuing new bilateral trade deals with non-EU countries (1)\n• Some trade redirected towards non-EU partners e.g. Australia, New Zealand (1)\n• Northern Ireland Protocol created unique trading arrangements (1) (max 5)' },
      { q: 'Describe how the growth of e-commerce has changed global trade.', marks: 4, markScheme: '• Enables small businesses and individuals to access global markets directly (1)\n• Reduces need for physical retail presence in foreign markets (1)\n• Increases cross-border trade in goods purchased online (1)\n• Growth of digital platforms (Amazon, Alibaba) as global trade intermediaries (1)\n• Challenges traditional trade measurement and regulation (1) (max 4)' },
      { q: 'Explain how Special Economic Zones (SEZs) are used to promote trade and attract investment.', marks: 5, markScheme: '• Designated areas with special regulations different from the rest of the country (1)\n• Offer tax incentives and reduced tariffs to attract foreign investment (1)\n• Streamlined bureaucracy and regulations for businesses (1)\n• Improved infrastructure to support export-oriented production (1)\n• Aim to promote manufacturing, exports and job creation (1)\n• Example: Shenzhen (China) transformed from fishing village to major manufacturing hub (1) (max 5)' },
      { q: 'Explain two impacts of commodity price fluctuations on developing economies.', marks: 4, markScheme: '• Government revenue instability: economies dependent on commodity exports face budget uncertainty (1)\n• Developed point: makes long-term planning and investment in services difficult (1)\n• Poverty and livelihoods: farmers and workers affected by falling prices (1)\n• Developed point: may lead to food insecurity if agricultural prices collapse (1)' },
      { q: 'Explain how colonialism has influenced current global trade patterns.', marks: 6, markScheme: '• Colonial powers structured economies of colonies for raw material extraction (1)\n• Trade routes established between colony and colonial power persist (1)\n• Former colonies remain dependent on primary commodity exports (1)\n• Infrastructure built to serve export routes, not domestic development (1)\n• Post-colonial trade agreements maintain economic links (1)\n• Language and cultural ties facilitate continued trade with former colonial powers (1)\n• Unequal power relationships in trade persist from colonial era (1) (max 6)' },
      { q: 'Explain how trade liberalisation can have both positive and negative effects on countries.', marks: 6, markScheme: '• Positive: lower prices for consumers through increased competition (1)\n• Positive: access to wider range of goods and services (1)\n• Positive: export opportunities for competitive industries (1)\n• Negative: domestic industries may be unable to compete with imports (1)\n• Negative: job losses in uncompetitive sectors (1)\n• Negative: increased inequality if benefits concentrated in certain sectors/regions (1)\n• Impact depends on the country\'s economic structure and readiness (1) (max 6)' },

      // 8-9 mark questions (10)
      { q: 'Explain how global trade patterns reflect and reinforce inequalities between countries. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of how trade creates and maintains inequality with well-developed examples. Clear chain of reasoning.\nLevel 2 (4-6 marks): Some explanation with partial examples.\nLevel 1 (1-3 marks): Basic description of trade inequality.\n\nIndicative content:\n• Core-periphery model: developed countries dominate trade in high-value goods\n• Developing countries often locked into primary commodity exports\n• Terms of trade disadvantage: declining commodity prices vs rising manufactured goods prices\n• Trade barriers in developed countries restrict market access\n• TNCs extract value from developing countries\n• Brain drain and capital flight from poorer to richer countries\n• Trade rules set by powerful nations in organisations like WTO\n• Historical colonial trade patterns persist\n• Examples: coffee, cocoa, mineral exports from Africa; manufactured imports from Asia/Europe' },
      { q: 'Assess the extent to which free trade agreements benefit all participating countries equally.', marks: 9, markScheme: 'Level 3 (7-9 marks): Thorough assessment with balanced consideration. Clear judgement supported by examples.\nLevel 2 (4-6 marks): Some assessment with partial examples.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nBenefits to all:\n• Increased market access and trade volumes\n• Consumer benefits from lower prices and greater choice\n• Efficiency gains from specialisation\nUnequal benefits:\n• Larger, more competitive economies gain more\n• Weaker industries in smaller countries may be destroyed\n• Power asymmetries in negotiations\n• Rules may favour developed country interests\n• Geographic proximity affects benefits\nExamples:\n• NAFTA/USMCA: USA vs Mexico impacts\n• EU: Germany vs Greece\n• Assessment of whether FTAs widen or narrow inequality' },
      { q: 'Explain how China\'s growing role in global trade has changed international trade patterns and relationships.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of China\'s impact on multiple aspects of global trade. Well-evidenced.\nLevel 2 (4-6 marks): Some aspects of China\'s trade impact discussed.\nLevel 1 (1-3 marks): Basic description of China\'s trade growth.\n\nIndicative content:\n• World\'s largest exporter of manufactured goods\n• Huge demand for raw materials from Africa, Latin America, Australia\n• Belt and Road Initiative creating new trade infrastructure and routes\n• South-South trade growth challenging traditional North-South patterns\n• Competition with established manufacturers in Europe and North America\n• Investment in African infrastructure in exchange for resource access\n• Trade tensions with USA (tariffs, technology competition)\n• Growth of Chinese TNCs operating globally\n• Impact on global supply chains' },
      { q: 'Explain the advantages and disadvantages of a country depending on primary commodity exports for economic development.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed and balanced explanation with clear understanding of the development implications.\nLevel 2 (4-6 marks): Some advantages and disadvantages with partial development.\nLevel 1 (1-3 marks): Basic identification of points.\n\nIndicative content:\nAdvantages:\n• Exploits natural comparative advantage\n• Can generate significant export revenue (e.g. oil-exporting nations)\n• Creates employment in extraction and agriculture\n• Can fund development through resource revenues\nDisadvantages:\n• Price volatility creates economic instability\n• Resource curse: wealth concentrated, corruption, conflict\n• Dutch disease: commodity exports inflate currency, harming other sectors\n• Environmental degradation from extraction\n• Limited value added compared to manufacturing\n• Declining terms of trade over time\n• Dependency on global demand\n• Examples: Nigeria (oil), DRC (minerals), Ghana (cocoa)' },
      { q: 'Assess the effectiveness of fair trade as a strategy for addressing global trade inequalities.', marks: 9, markScheme: 'Level 3 (7-9 marks): Thorough assessment with balanced consideration of strengths and limitations. Well-exemplified.\nLevel 2 (4-6 marks): Some assessment with partial evidence.\nLevel 1 (1-3 marks): Basic description of fair trade.\n\nIndicative content:\nStrengths:\n• Guaranteed minimum price provides stability\n• Social premium funds community development\n• Improved working conditions and environmental standards\n• Empowerment of small-scale producers\n• Consumer awareness of trade justice\nLimitations:\n• Small scale: only a tiny fraction of global trade\n• Certification costs exclude poorest producers\n• Consumer willingness to pay premium is limited\n• Doesn\'t address structural causes of trade inequality\n• Debate about whether it distorts markets\n• Some critics argue it keeps producers in low-value activities\nAssessment:\n• Valuable but insufficient alone\n• Needs to be part of broader trade reform' },
      { q: 'Explain how access to trade affects the development prospects of landlocked countries.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of how landlocked status affects trade and development. Clear evidence and examples.\nLevel 2 (4-6 marks): Some explanation with partial development.\nLevel 1 (1-3 marks): Basic identification of challenges.\n\nIndicative content:\n• No direct access to sea ports increases transport costs\n• Dependent on neighbouring countries for transit routes\n• Vulnerable to political instability in transit countries\n• Higher trade costs reduce competitiveness in global markets\n• Limited access to global shipping networks\n• Borders and customs add time and cost\n• May face unfavourable transit fees\n• Infrastructure challenges in mountainous/remote areas\n• Mitigation: regional cooperation, transport corridors, air freight\n• Examples: Ethiopia, Bolivia, Nepal, Central Asian states\n• Some landlocked countries succeed through other advantages e.g. Botswana (diamonds, good governance)' },
      { q: 'Explain how trade agreements and organisations attempt to manage global trade. Assess their effectiveness.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation with clear assessment of effectiveness. Well-evidenced.\nLevel 2 (4-6 marks): Some explanation and assessment.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• WTO: sets rules, dispute resolution, promotes liberalisation\n• Bilateral FTAs: reduce barriers between two countries\n• Regional blocs (EU, ASEAN, AU): deeper integration within regions\n• IMF/World Bank: structural adjustment, trade-related lending\nEffectiveness:\n• WTO Doha round stalled: developing country concerns not addressed\n• Proliferation of bilateral deals undermines multilateral system\n• Power imbalances in negotiations\n• Dispute resolution system works but favours those with legal resources\n• Trade has grown enormously but benefits unevenly distributed\n• Rising protectionism challenges rules-based system' },
      { q: 'Explain how ethical consumption and consumer choices can influence global trade patterns.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of how consumer behaviour affects trade with evidence. Critical assessment.\nLevel 2 (4-6 marks): Some explanation with partial evidence.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Fair trade purchasing supports ethical supply chains\n• Consumer boycotts can pressure companies to change practices\n• Demand for sustainably sourced products (FSC timber, MSC fish)\n• Local food movements reduce food miles\n• Fast fashion criticism driving some supply chain improvements\n• Social media amplifies consumer campaigns\n• Limitations: ethical products often more expensive\n• Consumer awareness varies by country and demographic\n• Individual choices vs systemic change debate\n• Corporate greenwashing may mislead consumers\n• Scale of ethical consumption still small relative to total trade' },
      { q: 'Explain how trade can both promote and hinder sustainable development.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced and detailed explanation of both promotion and hindrance with clear development links.\nLevel 2 (4-6 marks): Some points on both sides with partial development.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nPromotes sustainable development:\n• Economic growth creates resources for investment in services\n• Technology transfer improves productivity\n• Job creation and poverty reduction\n• Competition drives efficiency\n• Access to goods and services improving quality of life\nHinders sustainable development:\n• Resource extraction for export causes environmental degradation\n• Race to the bottom: countries lower environmental/labour standards\n• Dependency on volatile commodity markets\n• Increased transport emissions from global trade\n• Exploitation of workers in export processing zones\n• Profits repatriated by TNCs rather than reinvested locally\n• Widening inequality between and within countries' },
      { q: 'Assess the impacts of trade disputes and trade wars on the global economy. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed assessment of impacts with well-developed examples. Clear understanding of global interconnections.\nLevel 2 (4-6 marks): Some impacts assessed with partial examples.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Tariff escalation between major economies (e.g. US-China trade war)\n• Increased costs for businesses and consumers\n• Supply chain disruption and reshoring\n• Reduced global trade volumes and economic growth\n• Currency instability and financial market volatility\n• Developing countries caught in crossfire (reduced demand for exports)\n• Retaliation cycles escalating tensions\n• Impact on rules-based trading system\n• Some sectors benefit from protectionism short-term\n• Long-term costs of trade fragmentation\n• Geopolitical implications' },

      // 12-20 mark questions (5)
      { q: '"Global trade benefits developed countries at the expense of developing countries." To what extent do you agree with this statement?', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough and balanced evaluation with clear judgement. Well-supported by evidence and examples throughout.\nLevel 3 (9-12 marks): Good discussion with some balance and evidence.\nLevel 2 (5-8 marks): Some relevant points with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nAgreed:\n• Trade rules set by developed countries\n• Primary commodity dependence and declining terms of trade\n• TNC profit repatriation\n• Brain drain and capital flight\n• Structural adjustment conditions imposed on developing countries\n• Trade barriers protecting developed country agriculture\nDisagreed:\n• Some developing countries have benefited enormously (e.g. China, Vietnam, Bangladesh)\n• Trade has lifted millions out of poverty\n• Technology transfer and knowledge spillovers\n• South-South trade growing\n• Some developed country communities harmed by trade (deindustrialisation)\nEvaluation:\n• Not all developing countries are the same\n• Winners and losers within all countries\n• Trade itself is neutral; rules and structures determine outcomes\n• Historical context matters' },
      { q: 'Evaluate the role of TNCs in shaping global trade patterns and their impacts on host and home countries.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation considering multiple impacts on both host and home countries. Balanced judgement.\nLevel 3 (9-12 marks): Good coverage with some evaluation.\nLevel 2 (5-8 marks): Describes TNC activities with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nHost countries (where TNCs operate):\n• Job creation and skills transfer (+)\n• Investment in infrastructure (+)\n• Tax revenue (+)\n• Technology transfer (+)\n• Exploitation of workers and resources (-)\n• Profit repatriation (-)\n• Environmental damage (-)\n• Competition destroys local businesses (-)\nHome countries (HQ location):\n• Profits and dividends for shareholders (+)\n• Cheaper goods for consumers (+)\n• Job losses from offshoring (-)\n• Tax avoidance through transfer pricing (-)\nTrade patterns:\n• Intra-firm trade dominates global flows\n• Global supply chains determined by TNC decisions\n• Investment flows follow TNC strategies\n• Named TNC examples' },
      { q: 'Assess the extent to which trade liberalisation has been a positive force for global development.', marks: 12, markScheme: 'Level 4 (10-12 marks): Thorough assessment with balanced consideration of evidence. Clear judgement.\nLevel 3 (7-9 marks): Good assessment with some balance.\nLevel 2 (4-6 marks): Some points with limited assessment.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nPositive:\n• Global GDP growth and poverty reduction\n• Consumer benefits: lower prices, greater choice\n• Economic specialisation and efficiency\n• Integration of developing countries into global economy\n• Growth of middle class in emerging economies\nNegative:\n• Widening inequality between and within countries\n• Environmental degradation\n• Race to the bottom in labour and environmental standards\n• Vulnerability of developing countries to external shocks\n• Loss of policy space for industrial development\n• Cultural homogenisation\nAssessment:\n• Benefits real but unevenly distributed\n• Need for managed rather than unregulated liberalisation\n• Importance of domestic policies alongside trade openness' },
      { q: 'Discuss the challenges and opportunities that changing global trade patterns present for the UK economy.', marks: 20, markScheme: 'Level 5 (17-20 marks): Sophisticated discussion with well-developed analysis of multiple challenges and opportunities. Sustained, evidenced argument.\nLevel 4 (13-16 marks): Detailed discussion with good range of points and evidence.\nLevel 3 (9-12 marks): Some discussion with partial development.\nLevel 2 (5-8 marks): Limited discussion.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nChallenges:\n• Post-Brexit trade friction with EU (largest trading partner)\n• Competition from emerging economies in manufacturing and services\n• Supply chain vulnerabilities exposed by COVID-19\n• Geopolitical tensions affecting trade routes and partnerships\n• Decline of traditional industries\n• Need to meet climate commitments while trading globally\nOpportunities:\n• New bilateral trade deals with non-EU countries\n• Growth of service exports (finance, technology, education, creative industries)\n• Green economy and renewable energy technology exports\n• Digital economy and e-commerce growth\n• Commonwealth trading relationships\n• Freeports and enterprise zones\nDiscussion:\n• UK\'s changing role in global trade\n• Regional impacts within UK\n• Skills and workforce implications\n• Balance between free trade and protectionism\n• Long-term strategic direction' },
      { q: 'To what extent can trade alone drive sustainable economic development in low-income countries?', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation of trade\'s role alongside other development factors. Clear, justified judgement.\nLevel 3 (9-12 marks): Good discussion with some evaluation.\nLevel 2 (5-8 marks): Some relevant points with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nTrade can drive development:\n• Export revenue funds investment\n• Job creation reduces poverty\n• Technology transfer improves productivity\n• Integration into global markets\n• Success stories: East Asian Tigers, Vietnam\nTrade alone insufficient:\n• Need good governance and institutions\n• Education and healthcare investment essential\n• Infrastructure development required\n• Environmental sustainability must be considered\n• Trade benefits need equitable distribution\n• Commodity dependence creates vulnerability\n• Need for economic diversification\nOther factors needed:\n• Aid and investment\n• Debt relief\n• Domestic policy (education, health, governance)\n• International cooperation\n• Assessment of how trade interacts with other factors' },
    ],
  },

  '2.3': {
    name: 'Global Migration',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two push factors that cause people to emigrate from their country of origin.', marks: 2, markScheme: '• Poverty/lack of economic opportunities (1)\n• Conflict/war/persecution (1)\n• Natural disasters (1)\n• Political instability (1)\n• Environmental degradation (1) (any two)' },
      { q: 'Define the term "net migration".', marks: 2, markScheme: '• The difference between the number of immigrants (1)\n• And the number of emigrants in a given time period (1)' },
      { q: 'State two types of forced migration.', marks: 2, markScheme: '• Refugees fleeing conflict or persecution (1)\n• Asylum seekers (1)\n• Internally displaced persons (IDPs) (1)\n• Environmental/climate refugees (1)\n• Victims of human trafficking (1) (any two)' },
      { q: 'Define the term "economic migrant".', marks: 2, markScheme: '• A person who moves from one place to another (1)\n• Primarily to improve their economic situation/find better employment (1)' },
      { q: 'State two barriers to migration.', marks: 2, markScheme: '• Cost of travel/moving (1)\n• Immigration controls/visa restrictions (1)\n• Language barriers (1)\n• Physical barriers e.g. deserts, mountains, seas (1)\n• Discrimination in destination country (1) (any two)' },
      { q: 'State two consequences of emigration for the source country.', marks: 2, markScheme: '• Loss of working-age population/brain drain (1)\n• Remittance income sent back by migrants (1)\n• Reduced pressure on services and resources (1)\n• Loss of skills and talent (1)\n• Ageing population (1) (any two)' },
      { q: 'Define the term "diaspora".', marks: 2, markScheme: '• A dispersed population/community of people (1)\n• Who share a common origin/homeland but live outside it (1)' },
      { q: 'State two pull factors attracting migrants to a destination country.', marks: 2, markScheme: '• Better employment opportunities/higher wages (1)\n• Political stability and safety (1)\n• Better education and healthcare (1)\n• Family reunification (1)\n• Higher quality of life (1) (any two)' },
      { q: 'State two ways in which migration patterns have changed in recent decades.', marks: 2, markScheme: '• Increase in global migration flows overall (1)\n• Greater diversity of origin and destination countries (1)\n• Growth of South-South migration (1)\n• Increase in forced migration/refugee movements (1)\n• Feminisation of migration (1) (any two)' },
      { q: 'Define the term "refugee" as defined by the UN.', marks: 3, markScheme: '• A person who has been forced to flee their country (1)\n• Because of persecution, war, or violence (1)\n• Based on race, religion, nationality, political opinion, or membership of a social group (1)' },

      // 4-6 mark questions (15)
      { q: 'Explain how Lee\'s migration model helps to explain migration decisions.', marks: 6, diagram: true, markScheme: '• Push factors at origin: negative aspects that encourage people to leave (1)\n• Pull factors at destination: positive aspects that attract people (1)\n• Intervening obstacles: barriers that make migration difficult (1)\n• Personal factors: individual circumstances that influence the decision (1)\n• Migration occurs when perceived benefits of moving outweigh costs (1)\n• Model recognises that factors affect different people differently (1)\n• Credit annotated diagram of the model' },
      { q: 'Explain how remittances affect the economies of source countries.', marks: 6, markScheme: '• Remittances are money sent by migrants back to families in their home country (1)\n• Can exceed the value of foreign aid in many developing countries (1)\n• Provide income for basic needs: food, housing, healthcare, education (1)\n• Stimulate local economies through increased spending (1)\n• Can fund small business development and investment (1)\n• Reduce poverty and inequality for recipient families (1)\n• However, can create dependency and inflation in local markets (1)\n• May reduce incentive for government to invest in development (1) (max 6)' },
      { q: 'Explain how migration can lead to cultural change in destination countries. Use an example.', marks: 6, markScheme: '• Introduction of new languages and linguistic diversity (1)\n• New religious practices and places of worship (1)\n• Culinary diversity: new cuisines, restaurants, food shops (1)\n• Cultural festivals and celebrations enriching community life (1)\n• Music, art, and literature influenced by migrant cultures (1)\n• Named example with specific cultural changes (1)\n• Can also create challenges: cultural friction, segregation (1) (max 6)' },
      { q: 'Explain the causes of the European migration crisis from 2015 onwards.', marks: 6, markScheme: '• Civil war in Syria created millions of refugees (1)\n• Conflict and instability in Iraq, Afghanistan, Eritrea, Libya (1)\n• Persecution of minorities in origin countries (1)\n• Poverty and lack of economic opportunities in origin countries (1)\n• Perception of Europe as safe and prosperous (pull factors) (1)\n• Smuggling networks facilitated irregular border crossings (1)\n• Geographic proximity and established migration routes (1) (max 6)' },
      { q: 'Explain how brain drain affects developing countries.', marks: 5, markScheme: '• Loss of educated and skilled workers who emigrate to developed countries (1)\n• Healthcare and education sectors particularly affected e.g. doctors, nurses, teachers (1)\n• Reduces quality of services available to remaining population (1)\n• Country loses return on investment in education and training (1)\n• Limits economic growth and innovation potential (1)\n• Can be partially offset by remittances and return migration/brain circulation (1) (max 5)' },
      { q: 'Explain the economic impacts of immigration on destination countries.', marks: 6, markScheme: '• Fills labour shortages in key sectors (healthcare, agriculture, construction) (1)\n• Contributes to economic growth through labour force expansion (1)\n• Migrants pay taxes and contribute to public finances (1)\n• Entrepreneurship: migrants start new businesses (1)\n• May depress wages in some low-skilled sectors due to competition (1)\n• Potential pressure on housing and public services (1)\n• Fiscal impact depends on age, skills, and employment of migrants (1) (max 6)' },
      { q: 'Explain why some migration is described as "forced" rather than "voluntary".', marks: 5, markScheme: '• Forced migrants have no realistic choice but to move (1)\n• Driven by threats to life: conflict, persecution, violence (1)\n• Environmental disasters or climate change making areas uninhabitable (1)\n• Differs from voluntary/economic migration where people choose to move for better opportunities (1)\n• Legal distinction: forced migrants may qualify for refugee status and international protection (1)\n• In practice, the boundary between forced and voluntary is often blurred (1) (max 5)' },
      { q: 'Explain two consequences of rural-to-urban migration in developing countries.', marks: 4, markScheme: '• Rapid urbanisation creates growth of informal settlements/slums (1)\n• Strain on urban services: water, sanitation, healthcare, education (1)\n• Rural areas lose working-age population affecting agricultural productivity (1)\n• Remittances from urban migrants may support rural families (1)' },
      { q: 'Explain how government immigration policies attempt to manage migration flows.', marks: 6, markScheme: '• Points-based systems select migrants with needed skills (1)\n• Visa quotas limit numbers from specific countries or categories (1)\n• Border controls and surveillance restrict irregular entry (1)\n• Asylum processing determines eligibility for refugee protection (1)\n• Integration policies (language requirements, citizenship tests) manage settlement (1)\n• Bilateral agreements with source/transit countries control flows (1)\n• Deterrence policies (detention, deportation) discourage irregular migration (1) (max 6)' },
      { q: 'Explain how migration has shaped the demographic structure of a named country or region.', marks: 5, markScheme: '• Named country/region (1)\n• Immigration of working-age adults changes age structure (1)\n• Higher birth rates among migrant communities increase young population (1)\n• Emigration from rural areas creates ageing populations (1)\n• Gender-selective migration creates imbalanced sex ratios (1)\n• Ethnic composition changes through sustained migration flows (1) (max 5)' },
      { q: 'Explain how physical geography can influence migration routes and patterns.', marks: 4, markScheme: '• Mountain ranges, deserts and oceans act as barriers (1)\n• Migrants may follow coastal routes or river valleys as natural corridors (1)\n• Sea crossings (e.g. Mediterranean) create dangerous but used routes (1)\n• Climate and terrain affect feasibility of overland migration (1)\n• Climate change creating new push factors in vulnerable regions (1) (max 4)' },
      { q: 'Explain how social networks influence migration decisions and settlement patterns.', marks: 5, markScheme: '• Existing migrant communities in destination attract new migrants (chain migration) (1)\n• Networks provide information about opportunities and conditions (1)\n• Offer practical support: housing, employment contacts, language assistance (1)\n• Reduce risks and costs of migration (1)\n• Create ethnic enclaves/clustering in specific neighbourhoods (1)\n• Social media and communication technology strengthen transnational networks (1) (max 5)' },
      { q: 'Explain the difference between asylum seekers and refugees.', marks: 4, markScheme: '• An asylum seeker is a person who has applied for international protection (1)\n• But whose claim has not yet been assessed/decided (1)\n• A refugee is a person whose claim for protection has been granted (1)\n• Or who meets the UN definition of fleeing persecution, war or violence (1)\n• Not all asylum seekers will be recognised as refugees (1) (max 4)' },
      { q: 'Explain how climate change may increase future migration flows.', marks: 5, markScheme: '• Sea level rise threatening low-lying coastal areas and island nations (1)\n• Increased drought and desertification in semi-arid regions (1)\n• More frequent extreme weather events (floods, cyclones) displacing populations (1)\n• Agricultural disruption reducing food security (1)\n• Water scarcity creating resource conflicts (1)\n• Predicted 200+ million climate migrants by 2050 (1) (max 5)' },
      { q: 'Explain why the UK has experienced significant immigration in recent decades.', marks: 5, markScheme: '• Strong economy and labour market demand (1)\n• English language widely spoken globally (1)\n• EU freedom of movement (pre-Brexit) attracted European workers (1)\n• Commonwealth links attracting migrants from former colonies (1)\n• Reputation for education and healthcare (1)\n• Family reunification with established migrant communities (1)\n• Asylum seekers fleeing conflict (1) (max 5)' },

      // 8-9 mark questions (10)
      { q: 'Explain how international migration has both positive and negative impacts on destination countries. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed and balanced explanation with well-developed examples. Clear understanding of complexity.\nLevel 2 (4-6 marks): Some positive and negative impacts with partial examples.\nLevel 1 (1-3 marks): Basic description of impacts.\n\nIndicative content:\nPositive:\n• Economic contribution: fills labour shortages, pays taxes\n• Cultural enrichment: diversity, cuisine, arts\n• Demographic benefit: younger population counteracts ageing\n• Innovation and entrepreneurship\n• Skills and knowledge transfer\nNegative:\n• Pressure on housing and public services\n• Potential wage depression in some sectors\n• Social tensions and cultural friction\n• Political backlash and rise of anti-immigrant sentiment\n• Integration challenges\nExamples from specific countries/cities' },
      { q: 'Assess the extent to which migration is driven by economic factors.', marks: 9, markScheme: 'Level 3 (7-9 marks): Thorough assessment considering economic factors alongside other drivers. Clear judgement with examples.\nLevel 2 (4-6 marks): Some assessment with partial evidence.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nEconomic factors:\n• Wage differentials between countries\n• Employment opportunities\n• Poverty and livelihood insecurity\n• Economic restructuring and job losses\nOther factors:\n• Conflict and persecution (forced migration)\n• Environmental/climate change\n• Social networks and family reunification\n• Educational opportunities\n• Political freedoms\n• Personal aspirations and lifestyle choices\nAssessment:\n• Economic factors often primary but rarely sole driver\n• Different types of migration have different primary drivers\n• Factors interact and reinforce each other\n• Distinction between root causes and immediate triggers' },
      { q: 'Explain how a named international migration flow has impacted both the source and destination countries.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed case study knowledge with thorough analysis of impacts on both countries. Well-evidenced.\nLevel 2 (4-6 marks): Some impacts on both countries discussed.\nLevel 1 (1-3 marks): Basic description of migration flow.\n\nIndicative content (e.g. Poland to UK, Mexico to USA, Syria to Turkey/Germany, or other valid example):\nSource country impacts:\n• Economic: remittances, brain drain, labour shortages\n• Demographic: ageing population, gender imbalance\n• Social: family separation, cultural change\nDestination country impacts:\n• Economic: labour supply, economic contribution, fiscal impact\n• Demographic: population growth, diversity\n• Social: cultural change, integration challenges\n• Political: policy responses, public opinion\n• Specific data and evidence for the named example' },
      { q: 'Explain how the management of refugee crises raises ethical and practical challenges. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of both ethical and practical challenges with well-developed examples.\nLevel 2 (4-6 marks): Some challenges discussed with partial examples.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nEthical challenges:\n• Duty to protect vs national sovereignty\n• How to share responsibility fairly between countries\n• Rights of refugees vs concerns of host populations\n• Distinguishing refugees from economic migrants\n• Treatment of unaccompanied children\nPractical challenges:\n• Scale of displacement overwhelms host country capacity\n• Providing shelter, food, healthcare, education\n• Security concerns and screening\n• Integration vs temporary protection\n• Cost of hosting large refugee populations\nExamples: Syrian refugee crisis, Afghan displacement, Rohingya crisis' },
      { q: 'Explain how migration policies reflect the political and economic priorities of governments.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation linking policies to priorities with clear examples. Nuanced understanding.\nLevel 2 (4-6 marks): Some links between policy and priorities.\nLevel 1 (1-3 marks): Basic description of policies.\n\nIndicative content:\nEconomic priorities:\n• Selective immigration: points systems attract skilled workers\n• Seasonal worker schemes for agriculture\n• Student visas to attract tuition fees and talent\n• Labour market needs drive visa categories\nPolitical priorities:\n• Border security and sovereignty rhetoric\n• Electoral pressures: public opinion on immigration\n• Security concerns post-9/11\n• Human rights obligations vs domestic politics\nExamples:\n• Australia points system\n• UK post-Brexit immigration system\n• EU freedom of movement\n• Trump border wall\n• How policies change with government changes' },
      { q: 'Explain how globalisation has influenced patterns and processes of international migration.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple ways globalisation influences migration. Well-evidenced.\nLevel 2 (4-6 marks): Some links between globalisation and migration.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Cheaper and faster transport makes long-distance migration feasible\n• Global communication networks spread information about opportunities\n• TNC operations create demand for skilled workers across borders\n• Global media creates awareness of lifestyle differences\n• Economic globalisation creates winners and losers, pushing and pulling migration\n• Free trade agreements sometimes include labour mobility\n• Global supply chains create demand for migrant labour\n• Social media maintains transnational networks\n• Globalisation of education: international student mobility\n• Counter-trend: some globalisation effects reduce need to migrate (remote work)' },
      { q: 'Explain how internal migration within a country can create regional inequalities. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation with clear chain of reasoning and examples.\nLevel 2 (4-6 marks): Some explanation with partial examples.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Rural-urban migration concentrates population and resources in cities\n• Rural areas experience depopulation, service decline, ageing\n• Urban areas gain working-age population and economic dynamism\n• Brain drain from peripheral to core regions\n• Selective migration: young, educated, ambitious leave first\n• Creates cumulative causation: success attracts more investment and people\n• Neglected regions fall further behind\n• Examples: UK north-south divide, China\'s rural-urban migration\n• Government attempts to address regional imbalance' },
      { q: 'Assess the contribution of migrants to the social and economic development of the UK.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed and balanced assessment with clear evidence. Well-developed argument.\nLevel 2 (4-6 marks): Some assessment with partial evidence.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nEconomic contribution:\n• NHS staffing: significant proportion of doctors and nurses are migrants\n• Agriculture: seasonal workers essential for food production\n• Construction, hospitality, technology sectors rely on migrant labour\n• Entrepreneurship: migrants start businesses at higher rates\n• Tax contributions and fiscal impact\nSocial contribution:\n• Cultural diversity and enrichment\n• Educational achievement\n• Community organisations and civic participation\n• Innovation and creativity\nChallenges:\n• Integration in some communities\n• Pressure on services in areas of high immigration\n• Public perception vs evidence\n• Overall assessment of net contribution' },
      { q: 'Explain how the concept of "migration corridors" helps us understand global migration patterns.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of the concept with multiple examples and clear understanding of what creates corridors.\nLevel 2 (4-6 marks): Some explanation with partial examples.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Migration corridors are established routes of significant migration flow between specific countries\n• Created by historical links: colonial ties, language, culture\n• Economic factors: wage differentials, labour demand\n• Geographic proximity reduces costs and risks\n• Social networks sustain flows through chain migration\n• Policy frameworks (e.g. EU freedom of movement) facilitate corridors\n• Examples: Mexico-USA, Turkey-Germany, India-Gulf States, Poland-UK\n• Corridors can be bidirectional (goods, remittances, ideas flow back)\n• Understanding corridors helps target policy and aid\n• Corridors shift over time as conditions change' },
      { q: 'Explain how migration experiences differ for men and women.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of gendered migration experiences with clear evidence.\nLevel 2 (4-6 marks): Some gender differences discussed.\nLevel 1 (1-3 marks): Basic identification of differences.\n\nIndicative content:\n• Women increasingly migrating independently (feminisation of migration)\n• Different sectors: women concentrated in domestic work, care, textiles\n• Men dominant in construction, agriculture, heavy industry\n• Women face greater vulnerability to exploitation and trafficking\n• Gender-based violence and sexual exploitation on migration routes\n• Family responsibilities: women may migrate to support children left behind\n• Or may be unable to migrate due to caring responsibilities\n• Differential access to legal migration routes\n• Integration experiences differ: employment, language, social networks\n• Remittance patterns may differ: women often send higher proportion of income\n• Cultural expectations affect migration decisions differently by gender' },

      // 12-20 mark questions (5)
      { q: '"International migration creates more problems than benefits for destination countries." Discuss this statement with reference to examples.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough and balanced discussion with clear judgement. Well-supported by specific examples.\nLevel 3 (9-12 marks): Good discussion with some balance and examples.\nLevel 2 (5-8 marks): Some relevant points with limited discussion.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nProblems:\n• Pressure on housing, healthcare, education\n• Social tensions and cultural friction\n• Political backlash and polarisation\n• Potential wage depression in low-skilled sectors\n• Integration challenges and segregation\n• Security concerns\nBenefits:\n• Economic growth and labour market contribution\n• Tax revenue and fiscal contribution\n• Cultural diversity and innovation\n• Demographic rejuvenation\n• Skills and knowledge\n• Entrepreneurship\nDiscussion:\n• Evidence on balance of impacts is complex\n• Varies by type of migration, context, and time frame\n• Perception vs reality\n• Short-term costs vs long-term benefits\n• Role of policy in maximising benefits and minimising problems\n• Named country examples' },
      { q: 'Evaluate the effectiveness of different approaches to managing international migration. Use examples.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation of multiple approaches with clear judgement of effectiveness. Well-exemplified.\nLevel 3 (9-12 marks): Good range of approaches evaluated with some examples.\nLevel 2 (5-8 marks): Describes approaches with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nBorder control:\n• Physical barriers, surveillance, patrols\n• Effectiveness: reduces some irregular entry but displacement effect\n• Examples: EU Frontex, US-Mexico border\nSelective immigration:\n• Points systems, visa categories, quotas\n• Effectiveness: attracts needed skills but may not address irregular flows\n• Examples: Australia, Canada, UK post-Brexit\nInternational cooperation:\n• Bilateral agreements, refugee sharing\n• Effectiveness: addresses root causes but politically difficult\n• Examples: EU-Turkey deal, Global Compact on Migration\nIntegration policies:\n• Language, education, citizenship pathways\n• Effectiveness: promotes social cohesion but costly and slow\nDeterrence:\n• Detention, deportation, offshore processing\n• Ethical concerns, questionable effectiveness\nOverall assessment: no single approach works; combination needed' },
      { q: 'To what extent can migration be considered a response to global inequality? Use examples.', marks: 20, markScheme: 'Level 5 (17-20 marks): Sophisticated analysis linking migration to multiple dimensions of inequality. Sustained, nuanced argument with excellent examples.\nLevel 4 (13-16 marks): Detailed discussion with good range of inequality dimensions.\nLevel 3 (9-12 marks): Some discussion with partial development.\nLevel 2 (5-8 marks): Limited discussion.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nMigration as response to inequality:\n• Economic inequality: wage differentials drive labour migration\n• Development inequality: seeking better healthcare, education, infrastructure\n• Political inequality: fleeing persecution, lack of freedoms\n• Environmental inequality: climate change disproportionately affecting poor countries\n• Historical inequality: colonial legacies creating current disparities\nComplicating factors:\n• Not the poorest who migrate (need resources to move)\n• Migration can reinforce inequality (brain drain)\n• Or reduce it (remittances, skills transfer)\n• Some migration not driven by inequality (lifestyle, family)\n• Forced migration from conflict may cut across income levels\nExtent:\n• Inequality is a necessary but not sufficient condition\n• Other factors also matter: networks, policy, individual agency\n• Migration both reflects and reshapes global inequalities\n• Implications for addressing root causes vs managing flows' },
      { q: 'Assess the challenges and opportunities that the global refugee crisis presents for host countries. Use examples.', marks: 12, markScheme: 'Level 4 (10-12 marks): Thorough assessment with balanced consideration of challenges and opportunities. Well-exemplified.\nLevel 3 (7-9 marks): Good range of points with some assessment.\nLevel 2 (4-6 marks): Describes challenges/opportunities with limited assessment.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nChallenges:\n• Cost of providing shelter, food, healthcare, education\n• Strain on infrastructure and services\n• Social tensions with host communities\n• Security concerns\n• Political pressures and public opinion\n• Long-term integration needs\nOpportunities:\n• Labour force contribution once settled\n• Cultural diversity and innovation\n• International aid funding to host countries\n• Demographic benefits for ageing societies\n• Building diplomatic relationships\n• Humanitarian leadership and reputation\nExamples:\n• Turkey (hosts most refugees globally)\n• Germany (2015 intake)\n• Jordan, Lebanon (Syrian refugees)\n• Assessment varies by context and policy response' },
      { q: '"Borders should be open to allow free movement of people, just as goods move freely in trade." Evaluate this statement.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation with well-developed arguments on both sides. Clear, justified conclusion.\nLevel 3 (9-12 marks): Good evaluation with some balance.\nLevel 2 (5-8 marks): Some relevant points with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nArguments for open borders:\n• Moral: freedom of movement as a human right\n• Economic: labour mobility increases global efficiency and GDP\n• Practical: reduces illegal migration and trafficking\n• Reduces inequality by allowing people to access opportunities\n• Historical: borders are relatively recent constructs\nArguments against:\n• National sovereignty and self-determination\n• Security concerns\n• Pressure on public services and welfare systems\n• Social cohesion and cultural preservation\n• Brain drain from developing countries\n• Environmental capacity limits\nEvaluation:\n• Middle ground: managed migration with humanitarian obligations\n• Difference between ideal and practical reality\n• Comparison with free movement zones (EU) and their challenges\n• Power dynamics: who benefits from open/closed borders?\n• Democratic legitimacy of immigration policy' },
    ],
  },

  '2.4': {
    name: 'Human Rights',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two human rights set out in the Universal Declaration of Human Rights (UDHR).', marks: 2, markScheme: '• Right to life, liberty and security of person (1)\n• Freedom from slavery and torture (1)\n• Right to education (1)\n• Freedom of expression/speech (1)\n• Right to work and fair pay (1) (any two)' },
      { q: 'Define the term "human rights".', marks: 2, markScheme: '• Fundamental freedoms and entitlements (1)\n• That belong to every person regardless of nationality, sex, ethnicity, religion or other status (1)' },
      { q: 'State two examples of human rights abuses.', marks: 2, markScheme: '• Forced labour/modern slavery (1)\n• Torture and inhumane treatment (1)\n• Denial of education (1)\n• Political imprisonment/detention without trial (1)\n• Gender-based violence (1)\n• Genocide/ethnic cleansing (1) (any two)' },
      { q: 'Define the term "sovereignty" in the context of human rights.', marks: 2, markScheme: '• The authority of a state to govern itself (1)\n• Without external interference, including in its treatment of its own citizens (1)' },
      { q: 'State two ways in which human rights can be promoted.', marks: 2, markScheme: '• International treaties and conventions (1)\n• NGO campaigns and advocacy (1)\n• Education and awareness raising (1)\n• Media reporting and exposure (1)\n• Legal systems and courts (1) (any two)' },
      { q: 'State two reasons why women\'s rights may be restricted in some countries.', marks: 2, markScheme: '• Cultural traditions and patriarchal social structures (1)\n• Religious interpretations limiting women\'s roles (1)\n• Legal discrimination in property, marriage, employment laws (1)\n• Lack of educational access for girls (1)\n• Political exclusion of women from decision-making (1) (any two)' },
      { q: 'Define the term "intervention" in the context of human rights.', marks: 3, markScheme: '• Action taken by external actors (states, organisations) (1)\n• To influence or change a situation within another country (1)\n• Where human rights abuses are occurring or threatened (1)' },
      { q: 'State two organisations that work to protect human rights globally.', marks: 2, markScheme: '• United Nations (UN) / UN Human Rights Council (1)\n• Amnesty International (1)\n• Human Rights Watch (1)\n• International Criminal Court (ICC) (1)\n• Red Cross/Red Crescent (1) (any two)' },
      { q: 'State two ways in which conflict can lead to human rights abuses.', marks: 2, markScheme: '• Civilians targeted through violence, bombing, displacement (1)\n• Use of sexual violence as a weapon of war (1)\n• Destruction of civilian infrastructure (schools, hospitals) (1)\n• Forced recruitment of child soldiers (1)\n• Restrictions on humanitarian aid access (1) (any two)' },
      { q: 'Define the term "geopolitics" in the context of human rights.', marks: 2, markScheme: '• The influence of political power, territory and international relations (1)\n• On decisions about whether and how to address human rights issues in different countries (1)' },

      // 4-6 mark questions (15)
      { q: 'Explain why there is debate about whether human rights are truly universal.', marks: 6, markScheme: '• UDHR claims universality: rights apply to all people everywhere (1)\n• Cultural relativism: different cultures have different values and norms (1)\n• Some argue UDHR reflects Western liberal values, not universal ones (1)\n• Religious perspectives may prioritise different rights or obligations (1)\n• Economic development: some governments argue civil rights must wait until basic needs are met (1)\n• Asian values debate: collective rights vs individual rights emphasis (1)\n• Power dynamics: who defines "universal" rights? (1) (max 6)' },
      { q: 'Explain how globalisation has affected human rights awareness and protection.', marks: 6, markScheme: '• Global media and internet enable rapid exposure of abuses worldwide (1)\n• Social media allows activists to organise and share information (1)\n• International NGOs operate globally to monitor and report abuses (1)\n• Global economic integration creates pressure for labour standards (1)\n• However, globalisation also creates new abuses: sweatshops, exploitation (1)\n• TNCs may exploit weak governance in developing countries (1)\n• Digital surveillance technologies enable state repression (1) (max 6)' },
      { q: 'Explain two ways in which the United Nations promotes and protects human rights.', marks: 4, markScheme: '• UN Human Rights Council monitors and reports on human rights situations worldwide (1)\n• Can conduct investigations and pass resolutions drawing attention to abuses (1)\n• UN treaties and conventions set international standards that states sign and ratify (1)\n• Monitoring bodies check compliance and issue recommendations to states (1)' },
      { q: 'Explain how gender inequality varies geographically and the factors that cause this variation.', marks: 6, markScheme: '• Gender inequality is most severe in parts of Sub-Saharan Africa, South Asia, and the Middle East (1)\n• Cultural and religious practices may restrict women\'s freedom and rights (1)\n• Legal frameworks: some countries have discriminatory laws on marriage, property, employment (1)\n• Education access: girls\' education restricted in some regions (1)\n• Economic factors: poverty intensifies gender inequality (1)\n• Political participation: women underrepresented in governance in many countries (1)\n• Progress varies: some countries have made significant advances (1) (max 6)' },
      { q: 'Explain how economic development can affect human rights.', marks: 6, markScheme: '• Higher income enables governments to invest in education, healthcare, housing (social/economic rights) (1)\n• Economic growth can create middle class that demands political rights (1)\n• However, rapid economic development can exploit workers (1)\n• Development projects may displace indigenous communities (1)\n• Resource extraction can violate environmental and land rights (1)\n• Some governments use development as justification for restricting civil liberties (1)\n• Inequality within developing economies can worsen rights for marginalised groups (1) (max 6)' },
      { q: 'Explain the role of NGOs in promoting human rights. Use an example.', marks: 5, markScheme: '• Research and documentation of human rights abuses (1)\n• Advocacy and campaigning to pressure governments and organisations (1)\n• Legal support for victims of human rights abuses (1)\n• Public education and awareness raising (1)\n• Named example (e.g. Amnesty International, Human Rights Watch) with specific detail of activities (1)' },
      { q: 'Explain why some governments restrict freedom of expression.', marks: 5, markScheme: '• To maintain political power and suppress opposition/dissent (1)\n• Control of information prevents organisation of resistance movements (1)\n• National security justification: preventing terrorism or unrest (1)\n• Cultural or religious sensitivities: controlling blasphemy or offensive content (1)\n• Censorship of media and internet to control narrative (1)\n• Examples: China\'s Great Firewall, North Korea, restrictions in authoritarian states (1) (max 5)' },
      { q: 'Explain how conflict affects the human rights of civilians. Use a named example.', marks: 6, markScheme: '• Physical violence: killing, injury, mutilation of civilians (1)\n• Displacement: creation of refugees and internally displaced persons (1)\n• Destruction of infrastructure: schools, hospitals, water supplies (1)\n• Sexual violence used as a weapon of war (1)\n• Restriction of movement and access to humanitarian aid (1)\n• Named conflict example with specific detail of rights abuses (1)' },
      { q: 'Explain how access to education is both a human right and a driver of other rights.', marks: 5, markScheme: '• Education is enshrined as a right in UDHR Article 26 (1)\n• Educating girls reduces child marriage and improves maternal health (1)\n• Literacy enables people to know and claim their other rights (1)\n• Education improves economic opportunities, fulfilling right to work (1)\n• Educated citizens can participate more effectively in democracy (1)\n• Denial of education perpetuates cycles of poverty and discrimination (1) (max 5)' },
      { q: 'Explain how international law attempts to protect human rights during conflict.', marks: 6, markScheme: '• Geneva Conventions establish rules for treatment of civilians and prisoners of war (1)\n• International humanitarian law prohibits targeting civilian populations (1)\n• International Criminal Court (ICC) prosecutes war crimes, genocide, crimes against humanity (1)\n• UN Security Council can authorise peacekeeping operations (1)\n• Responsibility to Protect (R2P) doctrine allows intervention to prevent mass atrocities (1)\n• Limitations: enforcement is weak, powerful states may ignore international law (1)\n• ICC lacks universal jurisdiction and some states refuse to cooperate (1) (max 6)' },
      { q: 'Explain why children are particularly vulnerable to human rights abuses.', marks: 5, markScheme: '• Physical vulnerability: cannot protect themselves from violence or exploitation (1)\n• Dependence on adults who may be abusers (1)\n• Child labour: millions of children work in hazardous conditions (1)\n• Child soldiers: recruited into armed groups in conflict zones (1)\n• Child marriage: especially affects girls, denying education and health (1)\n• Trafficking: children exploited for labour, sexual exploitation, organ harvesting (1) (max 5)' },
      { q: 'Explain how the media can play a role in exposing human rights abuses.', marks: 5, markScheme: '• Investigative journalism reveals hidden abuses to a global audience (1)\n• Photographs and video provide powerful evidence that is hard to deny (1)\n• Social media enables citizens to document and share abuses in real time (1)\n• International media attention creates pressure on governments to act (1)\n• However, media can also be manipulated or censored by repressive states (1)\n• Media fatigue and selective coverage mean some abuses receive little attention (1) (max 5)' },
      { q: 'Explain how indigenous peoples\' rights are often threatened by development projects.', marks: 5, markScheme: '• Development projects (dams, mines, plantations) take place on indigenous lands (1)\n• Communities may be forcibly displaced without adequate consultation or compensation (1)\n• Environmental damage destroys resources indigenous communities depend on (1)\n• Cultural heritage sites may be destroyed (1)\n• Rights to self-determination and free, prior and informed consent often ignored (1)\n• Example: Amazon deforestation, pipeline projects, mining in Africa/Asia (1) (max 5)' },
      { q: 'Explain two ways in which economic sanctions can be used to address human rights abuses.', marks: 4, markScheme: '• Trade sanctions restrict imports/exports, putting economic pressure on abusive governments (1)\n• This reduces government revenue and aims to make the cost of abuses outweigh the benefits (1)\n• Targeted sanctions freeze assets of individuals responsible for abuses (1)\n• This directly punishes decision-makers rather than the general population (1)' },
      { q: 'Explain how the right to water is connected to other human rights.', marks: 5, markScheme: '• Clean water is essential for the right to health (1)\n• Water collection burden (often on women and girls) affects right to education (1)\n• Water scarcity can create conflict, threatening right to life and security (1)\n• Water access affects food production and right to adequate food (1)\n• Privatisation of water can make it unaffordable, affecting right to adequate standard of living (1)' },

      // 8-9 mark questions (10)
      { q: 'Explain how geopolitical factors influence whether and how the international community responds to human rights abuses.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of multiple geopolitical factors with clear examples. Sophisticated understanding.\nLevel 2 (4-6 marks): Some factors discussed with partial examples.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Powerful states may be protected from criticism by allies (veto in UN Security Council)\n• Strategic interests: oil, trade, military bases influence response\n• Selectivity: some abuses receive attention while others are ignored\n• Cold War/post-Cold War: ideological alignment affected interventions\n• Double standards: Western nations criticise some countries but not allies\n• Economic relationships: trade partnerships may prevent action\n• Media coverage influences public pressure for response\n• Regional power dynamics and spheres of influence\n• Examples: response to abuses in Syria vs Saudi Arabia, China\'s treatment of Uyghurs vs Western response' },
      { q: 'Assess the effectiveness of international organisations in protecting human rights. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed assessment of effectiveness with balanced consideration and examples.\nLevel 2 (4-6 marks): Some assessment with partial examples.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nEffective:\n• UN treaties establish global standards and norms\n• ICC has prosecuted some war criminals\n• UN peacekeeping missions protect civilians\n• Human rights reporting creates accountability\n• International pressure has contributed to change\nLimitations:\n• Enforcement is weak; relies on state cooperation\n• UN Security Council paralysed by veto power\n• ICC has limited jurisdiction and capacity\n• Powerful states exempt themselves\n• Slow processes while abuses continue\n• Resources insufficient for global monitoring\nExamples of both success and failure' },
      { q: 'Explain how human rights abuses are linked to patterns of development and inequality. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of links with well-developed examples. Clear chain of reasoning.\nLevel 2 (4-6 marks): Some links identified with partial examples.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Poverty and low development increase vulnerability to exploitation\n• Weak governance in developing countries enables abuses\n• Economic inequality creates conditions for forced labour and trafficking\n• Resource extraction in developing countries causes environmental and land rights abuses\n• Gender inequality linked to lower development levels\n• Conflict (a major cause of abuses) more common in less developed regions\n• But abuses occur in developed countries too (modern slavery, discrimination)\n• Development is not linear path to rights protection\n• Examples at different scales and locations' },
      { q: 'Explain the tension between national sovereignty and international human rights norms.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of the tension with clear examples. Nuanced understanding.\nLevel 2 (4-6 marks): Some explanation of the tension.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Sovereignty: states have the right to govern without external interference\n• Human rights norms: international standards that apply regardless of borders\n• Tension: when a state abuses its own citizens, should others intervene?\n• Responsibility to Protect (R2P): sovereignty not absolute if government fails to protect\n• Governments use sovereignty to deflect criticism of internal affairs\n• Intervention risks: neo-colonialism, regime change, unintended consequences\n• International law tries to balance: treaties are voluntary, enforcement limited\n• Examples: Syria, Myanmar, North Korea\n• Question of who decides when intervention is justified' },
      { q: 'Explain how the struggle for human rights varies between different groups and regions. Use examples.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation covering multiple groups and regions with specific examples.\nLevel 2 (4-6 marks): Some groups and regions discussed.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nDifferent groups:\n• Women: gender equality struggles vary by region\n• LGBTQ+ communities: rights vary dramatically between countries\n• Ethnic minorities and indigenous peoples\n• Children: child labour, child marriage, child soldiers\n• Refugees and migrants\n• Religious minorities\nRegional variation:\n• Progress in some regions while others see regression\n• Different cultural, political, and economic contexts\n• Different priorities: civil/political vs economic/social rights\n• Colonial legacies affecting current rights situations\n• Examples from multiple regions with specific detail' },
      { q: 'Assess the role of technology in both promoting and threatening human rights.', marks: 9, markScheme: 'Level 3 (7-9 marks): Balanced assessment of technology\'s dual role with clear examples.\nLevel 2 (4-6 marks): Some points on both sides.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nPromoting rights:\n• Social media enables organisation and awareness (Arab Spring)\n• Citizen journalism documents abuses\n• Encrypted communication protects activists\n• Online platforms for petitions and campaigns\n• Data collection tracks abuses\nThreatening rights:\n• Mass surveillance by governments\n• Facial recognition technology\n• Social media used for hate speech and radicalisation\n• Digital divide excludes poorest from information\n• AI bias in criminal justice and other systems\n• Misinformation undermining democratic processes\n• Cyber attacks on activists and journalists\nAssessment:\n• Technology is a tool: impact depends on who controls it\n• Power dynamics determine outcomes\n• Need for digital rights framework' },
      { q: 'Explain how the concept of "Responsibility to Protect" (R2P) has been applied. Assess its effectiveness.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of R2P with assessment of application and effectiveness.\nLevel 2 (4-6 marks): Some explanation with partial assessment.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nConcept:\n• Three pillars: state responsibility, international assistance, decisive response\n• Applies to genocide, war crimes, ethnic cleansing, crimes against humanity\n• Adopted by UN World Summit 2005\nApplication:\n• Libya 2011: military intervention to protect civilians\n• Ivory Coast 2011: UN intervention during election crisis\n• Failure to apply: Syria, Myanmar, Yemen\nAssessment:\n• Libya case raised questions about regime change vs protection\n• Selective application undermines legitimacy\n• Political will and geopolitical interests determine application\n• Debate about whether R2P strengthens or undermines sovereignty\n• Overall mixed record' },
      { q: 'Explain how modern slavery and human trafficking represent major human rights challenges today.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of the scale, causes and nature of modern slavery with clear evidence.\nLevel 2 (4-6 marks): Some explanation with partial evidence.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Estimated 40+ million people in modern slavery globally\n• Forms: forced labour, debt bondage, sexual exploitation, domestic servitude\n• Causes: poverty, conflict, discrimination, weak governance\n• Trafficking networks operate across borders\n• Supply chains of TNCs may include forced labour\n• Vulnerability increased by migration and displacement\n• Affects all countries including developed nations\n• Challenges: hidden nature, fear of reporting, corruption\n• International efforts: Palermo Protocol, national modern slavery acts\n• Need for better enforcement, victim support, addressing root causes\n• Examples: cocoa industry, garment factories, domestic workers in Gulf states' },
      { q: 'Explain how the rights of women and girls have improved globally and assess the progress made.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed explanation of progress with balanced assessment. Well-evidenced.\nLevel 2 (4-6 marks): Some progress and assessment discussed.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nProgress:\n• Girls\' education enrollment increased significantly\n• More women in political leadership positions\n• Legal reforms: property rights, marriage laws, anti-discrimination\n• Declining rates of child marriage in some regions\n• Global awareness through #MeToo and similar movements\n• CEDAW convention ratified by most countries\nRemaining challenges:\n• Gender pay gap persists globally\n• Violence against women and girls remains widespread\n• Maternal mortality still high in developing countries\n• Underrepresentation in senior positions\n• Backlash against gender equality in some regions\nAssessment:\n• Uneven progress: some regions advancing, others stalling or reversing\n• Legal change doesn\'t always translate to lived reality\n• Intersectionality: poorest women face multiple disadvantages' },
      { q: 'Explain how the right to development can conflict with environmental rights.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of the tension with clear examples. Nuanced understanding.\nLevel 2 (4-6 marks): Some tension identified with partial examples.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Right to development: everyone entitled to participate in economic, social, cultural development\n• Environmental rights: right to clean air, water, healthy environment\n• Conflict: economic development often causes pollution, deforestation, resource depletion\n• Developing countries argue they should not be denied industrialisation that developed countries enjoyed\n• Climate justice: who bears the cost of environmental protection?\n• Indigenous communities vs development projects\n• Resource extraction for economic growth vs environmental protection\n• Examples: Amazon deforestation, coal mining in India, palm oil in Indonesia\n• Sustainable development as attempted resolution but difficult in practice\n• Intergenerational rights: current development vs future environmental rights' },

      // 12-20 mark questions (5)
      { q: '"Human rights are universal and non-negotiable." To what extent do you agree with this statement?', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation with well-developed arguments from multiple perspectives. Clear judgement.\nLevel 3 (9-12 marks): Good discussion with some balance.\nLevel 2 (5-8 marks): Some relevant points with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nAgreed (universalist position):\n• UDHR adopted by 193 UN member states\n• Human dignity transcends cultural differences\n• Minimum standards necessary for all humans\n• Rights protect vulnerable people from cultural practices that harm them\n• International law establishes universal norms\nDisagreed (relativist position):\n• UDHR reflects Western values at a specific historical moment\n• Cultural diversity means different societies prioritise different values\n• Individual rights may conflict with collective/community values\n• Religious and philosophical traditions offer alternative frameworks\n• Imposition of "universal" rights can be neo-colonial\nEvaluation:\n• Are some rights more universal than others (right to life vs specific political freedoms)?\n• Evolution of rights over time\n• Pragmatic vs philosophical universalism\n• Power dynamics in defining universality' },
      { q: 'Evaluate the extent to which international intervention is an effective response to human rights abuses. Use examples.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation with multiple types of intervention considered. Well-evidenced with clear judgement.\nLevel 3 (9-12 marks): Good evaluation with some examples.\nLevel 2 (5-8 marks): Describes interventions with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nTypes of intervention:\n• Military intervention: Libya 2011, Kosovo 1999\n• Economic sanctions: South Africa apartheid, Iran, Russia\n• Diplomatic pressure and UN resolutions\n• International courts and tribunals\n• Humanitarian intervention: aid, peacekeeping\nEffective:\n• End of apartheid partly due to international pressure\n• ICC convictions deter some future abuses\n• Peacekeeping has protected civilians in some cases\nIneffective:\n• Military intervention can cause more harm (Libya aftermath)\n• Sanctions often hurt ordinary people, not leaders\n• Selective application undermines credibility\n• Rwanda genocide: failure to intervene\n• Syria: international paralysis despite massive abuses\nEvaluation:\n• Context determines effectiveness\n• No perfect solution but inaction is also a choice\n• Combination of approaches often most effective' },
      { q: 'Discuss the challenges of protecting human rights in a globalised world. Use examples.', marks: 20, markScheme: 'Level 5 (17-20 marks): Exceptional understanding of complex interactions between globalisation and human rights. Sustained, nuanced argument.\nLevel 4 (13-16 marks): Detailed discussion with good range of challenges and examples.\nLevel 3 (9-12 marks): Some discussion with partial development.\nLevel 2 (5-8 marks): Limited discussion.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nChallenges:\n• TNCs operating across jurisdictions make accountability difficult\n• Global supply chains hide human rights abuses\n• Technology enables mass surveillance and repression\n• Powerful states resist scrutiny from international community\n• Migration creates stateless and vulnerable populations\n• Climate change creates new categories of rights violation\n• Cultural diversity makes consensus on rights difficult\n• International institutions lack enforcement power\n• Rise of populism and nationalism challenges international cooperation\n• Digital divide creates new inequalities\nOpportunities:\n• Global communication exposes abuses quickly\n• International NGO networks monitor rights worldwide\n• Growing body of international law and norms\n• Consumer pressure on corporations\n• Global solidarity movements\nDiscussion:\n• Globalisation creates both threats and tools for protection\n• Need for new frameworks to address global challenges\n• Role of different actors: states, organisations, individuals, corporations\n• Named examples throughout' },
      { q: 'Assess the extent to which gender equality can be achieved through legal changes alone.', marks: 12, markScheme: 'Level 4 (10-12 marks): Thorough assessment considering legal and non-legal factors. Clear judgement with examples.\nLevel 3 (7-9 marks): Good assessment with some balance.\nLevel 2 (4-6 marks): Some points with limited assessment.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nLegal changes:\n• Anti-discrimination laws establish equality in principle\n• Property and inheritance rights for women\n• Laws against domestic violence and sexual assault\n• Equal pay legislation\n• Political quotas for women\'s representation\nLimitations of legal approach:\n• Laws may not be enforced, especially in rural/remote areas\n• Cultural attitudes may not change with laws\n• Women may lack access to justice system\n• Intersecting inequalities (class, ethnicity) not addressed by gender laws alone\n• Backlash against legal changes\nOther factors needed:\n• Education and awareness\n• Economic empowerment\n• Cultural change through media and role models\n• Community-level programmes\n• Male engagement in gender equality\n• Examples: countries with good laws but poor outcomes vs limited laws but cultural change' },
      { q: '"Economic development is the most important factor in improving human rights." Evaluate this statement with reference to examples.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation considering economic development alongside other factors. Clear, justified judgement.\nLevel 3 (9-12 marks): Good discussion with some evaluation.\nLevel 2 (5-8 marks): Some relevant points with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nEconomic development supports rights:\n• Resources for education, healthcare, social protection\n• Educated, economically empowered citizens demand rights\n• Reduced poverty reduces vulnerability to exploitation\n• Economic growth creates middle class that demands political reform\n• Examples: South Korea, Taiwan democratised as they developed\nEconomic development insufficient:\n• Wealthy authoritarian states (Saudi Arabia, China) restrict civil liberties\n• Economic growth can increase inequality and exploitation\n• Development projects can violate indigenous and environmental rights\n• Resource curse: wealth from resources may fund repression\nOther factors:\n• Governance and political will\n• Cultural values and social norms\n• International pressure and cooperation\n• Civil society and activism\n• Education and awareness\n• Historical context and colonial legacy\nEvaluation:\n• Development is important but not deterministic\n• Type of development matters: inclusive vs extractive\n• Rights and development are mutually reinforcing' },
    ],
  },

  '2.5': {
    name: 'Power & Borders',
    questions: [
      // 2-3 mark questions (10)
      { q: 'State two types of power that a state can possess.', marks: 2, markScheme: '• Hard power (military and economic) (1)\n• Soft power (cultural influence, diplomacy, values) (1)\n• Smart power (combination of hard and soft) (1) (any two)' },
      { q: 'Define the term "sovereignty".', marks: 2, markScheme: '• The supreme authority of a state (1)\n• To govern itself and make decisions within its own territory without external interference (1)' },
      { q: 'State two functions of international borders.', marks: 2, markScheme: '• Control movement of people (immigration) (1)\n• Control movement of goods (trade/customs) (1)\n• Define the extent of a state\'s territory and legal jurisdiction (1)\n• Symbol of national identity and sovereignty (1) (any two)' },
      { q: 'Define the term "superpower".', marks: 2, markScheme: '• A state with dominant influence and power (1)\n• In military, economic, political and cultural spheres on a global scale (1)' },
      { q: 'State two characteristics of a nation-state.', marks: 2, markScheme: '• A defined territory with recognised borders (1)\n• A population sharing a common national identity/culture (1)\n• A sovereign government (1)\n• International recognition (1) (any two)' },
      { q: 'State two examples of supranational organisations.', marks: 2, markScheme: '• European Union (EU) (1)\n• United Nations (UN) (1)\n• NATO (1)\n• African Union (AU) (1)\n• ASEAN (1) (any two)' },
      { q: 'Define the term "autonomy" in the context of governance.', marks: 2, markScheme: '• The right of a region or group to self-governance (1)\n• Over some or all of their own affairs within a larger state (1)' },
      { q: 'State two ways in which borders can be contested.', marks: 2, markScheme: '• Territorial disputes between neighbouring states (1)\n• Separatist movements seeking independence (1)\n• Historical claims based on ethnic/cultural territory (1)\n• Maritime/resource disputes in border regions (1) (any two)' },
      { q: 'State two ways in which a country can exert soft power.', marks: 2, markScheme: '• Cultural exports: film, music, language, food (1)\n• Educational institutions attracting international students (1)\n• Diplomacy and international aid (1)\n• Values: democracy, human rights, rule of law (1)\n• Sport and international events (1) (any two)' },
      { q: 'Define the term "multi-polar world".', marks: 3, markScheme: '• A global power structure (1)\n• In which power is distributed among several states or blocs (1)\n• Rather than being dominated by one (unipolar) or two (bipolar) superpowers (1)' },

      // 4-6 mark questions (15)
      { q: 'Explain the difference between hard power and soft power, using examples.', marks: 6, markScheme: '• Hard power: the ability to influence others through coercion (1)\n• Uses military force, economic sanctions, threats (1)\n• Example: US military presence in the Middle East; Russian invasion of Ukraine (1)\n• Soft power: the ability to influence others through attraction (1)\n• Uses culture, values, diplomacy, institutions (1)\n• Example: British Council promoting UK culture; Hollywood spreading American values (1)' },
      { q: 'Explain how global governance organisations attempt to manage international relations.', marks: 6, markScheme: '• United Nations provides forum for diplomacy and collective decision-making (1)\n• UN Security Council can authorise military intervention and sanctions (1)\n• WTO sets rules for international trade (1)\n• International courts (ICJ, ICC) provide legal frameworks (1)\n• Regional organisations (EU, AU, ASEAN) manage regional affairs (1)\n• NGOs and civil society contribute to governance (1)\n• Limitations: relies on state cooperation, powerful states can resist (1) (max 6)' },
      { q: 'Explain why some borders are more contested than others.', marks: 6, markScheme: '• Colonial legacy: borders drawn without regard for ethnic or cultural boundaries (1)\n• Resource disputes: oil, gas, minerals, water in border regions (1)\n• Strategic significance: access to sea, trade routes, military advantage (1)\n• Ethnic and cultural divisions: nations split across borders (1)\n• Historical claims: different interpretations of historical territory (1)\n• Changing power dynamics: rising states challenging existing borders (1)\n• Examples: Israel-Palestine, India-Pakistan Kashmir, South China Sea (1) (max 6)' },
      { q: 'Explain how the European Union has affected the sovereignty of its member states.', marks: 6, markScheme: '• EU law takes precedence over national law in agreed areas (1)\n• Common trade policy: individual states cannot negotiate own trade deals (1)\n• Freedom of movement: states cannot fully control immigration from EU (1)\n• Common currency (eurozone): loss of independent monetary policy (1)\n• Environmental and consumer regulations set at EU level (1)\n• However, states retain sovereignty in many areas (defence, taxation, education) (1)\n• EU membership is voluntary; states can leave (Brexit) (1) (max 6)' },
      { q: 'Explain how economic power can be used to influence other countries.', marks: 5, markScheme: '• Trade agreements and preferential market access reward compliant states (1)\n• Economic sanctions restrict trade with countries that violate norms (1)\n• Foreign direct investment creates economic dependency (1)\n• Control of key resources (oil, rare earth minerals) gives leverage (1)\n• International financial institutions (IMF, World Bank) set conditions on lending (1)\n• Example: China\'s Belt and Road Initiative creating economic influence (1) (max 5)' },
      { q: 'Explain why some groups seek independence from existing states.', marks: 6, markScheme: '• Ethnic or cultural distinctiveness: group has separate identity from dominant population (1)\n• Historical grievances: past oppression, forced incorporation (1)\n• Economic factors: resource-rich regions may want to keep revenues (1)\n• Political underrepresentation in central government (1)\n• Desire for self-determination: right to govern own affairs (1)\n• External support or inspiration from other independence movements (1)\n• Examples: Scotland, Catalonia, Kurdistan, Tibet (1) (max 6)' },
      { q: 'Explain how the concept of sovereignty has been challenged in the 21st century.', marks: 6, markScheme: '• Globalisation: economic interdependence reduces policy autonomy (1)\n• Supranational organisations: states pool sovereignty e.g. EU (1)\n• International law: human rights norms override state prerogatives (1)\n• Responsibility to Protect: external intervention in domestic affairs (1)\n• Cyber threats: state borders do not contain digital threats (1)\n• Climate change: global problem requiring collective action beyond borders (1)\n• TNCs: economic power sometimes exceeding that of states (1) (max 6)' },
      { q: 'Explain how the balance of global power has shifted since the end of the Cold War.', marks: 6, markScheme: '• End of Cold War (1991): shift from bipolar to unipolar (US dominance) (1)\n• Rise of China as an economic and military power (1)\n• Re-emergence of Russia as an assertive power (1)\n• Rise of regional powers: India, Brazil, Turkey (1)\n• Relative decline of US influence in some areas (1)\n• Shift towards multi-polar or contested power structure (1)\n• EU as an economic bloc but limited military power (1) (max 6)' },
      { q: 'Explain how conflict over resources can affect international borders and relations.', marks: 5, markScheme: '• Water disputes: rivers crossing borders create conflict e.g. Nile, Mekong (1)\n• Oil and gas: maritime boundaries disputed where resources exist e.g. South China Sea (1)\n• Mineral resources: control of resource-rich territories contested e.g. DRC (1)\n• Arctic: melting ice opens new resource and shipping route disputes (1)\n• Resources can motivate territorial claims and border changes (1)\n• International law (UNCLOS) attempts to resolve maritime disputes but imperfectly (1) (max 5)' },
      { q: 'Explain how nationalism can both strengthen and threaten states.', marks: 6, markScheme: '• Strengthens: creates social cohesion and shared identity within a state (1)\n• Strengthens: motivates citizens to defend the state and contribute to public good (1)\n• Strengthens: supports state legitimacy and institutions (1)\n• Threatens: ethnic nationalism can exclude minorities and create conflict (1)\n• Threatens: sub-state nationalism/separatism can break states apart (1)\n• Threatens: aggressive nationalism can lead to international conflict (1)\n• Examples: Scottish independence movement, breakup of Yugoslavia, rise of populist nationalism (1) (max 6)' },
      { q: 'Explain how the United Nations Security Council operates and why it is criticised.', marks: 6, markScheme: '• Five permanent members (P5): USA, UK, France, Russia, China with veto power (1)\n• Ten non-permanent members elected for two-year terms (1)\n• Responsible for maintaining international peace and security (1)\n• Can authorise sanctions, peacekeeping operations, military action (1)\n• Criticised: P5 veto paralyses action when their interests are involved (1)\n• Criticised: P5 composition reflects 1945 power structure, not current world (1)\n• Criticised: developing world underrepresented, especially Africa (1) (max 6)' },
      { q: 'Explain how maritime borders and Exclusive Economic Zones (EEZs) are determined and why they are important.', marks: 5, diagram: true, markScheme: '• UNCLOS (UN Convention on the Law of the Sea) establishes rules (1)\n• Territorial sea extends 12 nautical miles from coast (1)\n• EEZ extends 200 nautical miles: state has rights over resources (1)\n• Continental shelf claims can extend further (1)\n• Important for fisheries, oil/gas, minerals, shipping routes (1)\n• Disputes arise where EEZs overlap or where island sovereignty is contested (1)\n• Credit annotated diagram of maritime zones (max 5)' },
      { q: 'Explain how the concept of "failed states" relates to issues of power and borders.', marks: 5, markScheme: '• A failed state is one that cannot provide basic functions of government (1)\n• Loss of control over territory: unable to enforce borders (1)\n• Inability to provide security, services, or rule of law (1)\n• Creates power vacuums exploited by armed groups, criminal networks (1)\n• Can lead to cross-border instability: refugees, terrorism, trafficking (1)\n• Examples: Somalia, Yemen, South Sudan (1) (max 5)' },
      { q: 'Explain how trade blocs can increase the collective power of member states.', marks: 5, markScheme: '• Larger combined market gives greater bargaining power in trade negotiations (1)\n• Economic integration creates larger GDP and economic influence (1)\n• Collective diplomatic weight in international organisations (1)\n• Shared resources and institutions reduce costs (1)\n• Can negotiate better terms with non-member states (1)\n• Example: EU as the world\'s largest trading bloc negotiating as one entity (1) (max 5)' },
      { q: 'Explain how cyberspace has created new challenges for state sovereignty and security.', marks: 5, markScheme: '• Internet does not respect physical borders; information flows freely (1)\n• States struggle to control online content within their territory (1)\n• Cyber attacks can target critical infrastructure without physical invasion (1)\n• State-sponsored hacking threatens other nations\' security (1)\n• Social media enables foreign interference in democratic processes (1)\n• Difficulty attributing cyber attacks to specific states (1) (max 5)' },

      // 8-9 mark questions (10)
      { q: 'Explain how the rise of China is changing the global balance of power. Use evidence.', marks: 9, markScheme: 'Level 3 (7-9 marks): Detailed and well-evidenced explanation of China\'s rising power across multiple dimensions. Clear understanding of implications.\nLevel 2 (4-6 marks): Some aspects of China\'s rise discussed with partial evidence.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nEconomic power:\n• World\'s second largest economy (by GDP), largest by PPP\n• Belt and Road Initiative: infrastructure investment in 70+ countries\n• Largest trading partner for many nations\nMilitary power:\n• Rapid military modernisation\n• South China Sea island building and territorial claims\n• Growing naval capability\nSoft power:\n• Confucius Institutes worldwide\n• Media expansion (CGTN)\n• Space programme\nPolitical power:\n• UN Security Council permanent member\n• Alternative development model to Western liberalism\n• Growing influence in international organisations\nImplications:\n• US-China rivalry as defining geopolitical dynamic\n• Challenges to rules-based international order\n• Multi-polar world emerging' },
      { q: 'Assess the effectiveness of the United Nations in maintaining global peace and security.', marks: 9, markScheme: 'Level 3 (7-9 marks): Thorough assessment with balanced consideration of successes and failures. Well-evidenced.\nLevel 2 (4-6 marks): Some assessment with partial evidence.\nLevel 1 (1-3 marks): Basic description of UN.\n\nIndicative content:\nSuccesses:\n• Peacekeeping operations have reduced violence in many conflicts\n• Diplomatic forum prevents some conflicts from escalating\n• Nuclear non-proliferation treaty\n• Humanitarian coordination saves lives\nFailures:\n• Security Council veto paralyses action (Syria, Ukraine)\n• Rwanda genocide: failure to prevent\n• Srebrenica massacre under UN protection\n• Unable to resolve Israeli-Palestinian conflict\n• North Korea nuclear programme\nAssessment:\n• More effective at managing minor conflicts than major power confrontations\n• Structural reform needed but politically difficult\n• Alternative: what would the world look like without the UN?\n• Need to consider full range of UN activities, not just security' },
      { q: 'Explain how borders in Africa reflect colonial legacy and assess the consequences.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of colonial border-drawing with thorough assessment of consequences.\nLevel 2 (4-6 marks): Some explanation with partial assessment.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nColonial legacy:\n• Borders drawn at Berlin Conference (1884-85) by European powers\n• Straight lines ignoring ethnic, linguistic, and cultural boundaries\n• Nations split across multiple states; rival groups forced into single states\n• Borders served colonial economic interests (resource extraction)\nConsequences:\n• Ethnic conflict within artificially created states\n• Separatist movements and border disputes\n• Weak national identity in some states\n• Inter-state conflicts over territory\n• Difficulty building stable governance\n• African Union policy of respecting existing borders to prevent chaos\n• Examples: Rwanda, DRC, Nigeria, Sudan/South Sudan' },
      { q: 'Explain how different types of governance affect the rights and freedoms of citizens. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed comparison of governance types with clear links to citizen rights. Well-exemplified.\nLevel 2 (4-6 marks): Some comparison with partial examples.\nLevel 1 (1-3 marks): Basic description of one governance type.\n\nIndicative content:\nDemocratic governance:\n• Free elections, rule of law, independent judiciary\n• Freedom of expression, assembly, religion\n• But democratic deficit: not all democracies equally free\n• Examples: UK, USA (but with flaws in practice)\nAuthoritarian governance:\n• Limited political freedoms, censorship, surveillance\n• State control of media and information\n• Restricted civil liberties but may provide stability/services\n• Examples: China, Russia, North Korea\nFailed/weak governance:\n• Inability to protect rights or provide services\n• Violence and insecurity\n• Examples: Somalia, Yemen\nTheocratic governance:\n• Religious law determines rights and freedoms\n• May restrict women\'s rights and religious minorities\n• Example: Iran, Saudi Arabia' },
      { q: 'Assess the extent to which globalisation has weakened the power of nation-states.', marks: 9, markScheme: 'Level 3 (7-9 marks): Thorough assessment with balanced evidence. Clear judgement.\nLevel 2 (4-6 marks): Some assessment with partial evidence.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nWeakened:\n• Economic globalisation reduces policy autonomy\n• TNCs can pressure governments with threat of relocation\n• International organisations impose rules and conditions\n• Global financial markets constrain economic policy\n• Climate change requires collective action beyond borders\n• Cyberspace challenges territorial control\nNot weakened:\n• States remain primary actors in international relations\n• Military power still concentrated in states\n• Pandemic response showed state power reasserting (border closures, lockdowns)\n• Rising nationalism and protectionism\n• States control immigration policy\n• Surveillance technology increases state power\nAssessment:\n• Power has changed form rather than disappeared\n• Varies by state: powerful states less affected\n• Globalisation and state power coexist in complex ways' },
      { q: 'Explain how the concept of "spheres of influence" operates in contemporary geopolitics. Use examples.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation with clear contemporary examples. Nuanced understanding.\nLevel 2 (4-6 marks): Some explanation with partial examples.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Spheres of influence: areas where a major power has dominant influence\n• Economic influence: trade, investment, aid creating dependency\n• Military influence: bases, alliances, security guarantees\n• Cultural influence: media, education, language\n• Contemporary examples:\n  - Russia: influence over former Soviet states (Ukraine, Belarus, Central Asia)\n  - China: growing influence in Southeast Asia, Africa, Central Asia\n  - USA: influence in Western Hemisphere, Europe, East Asia through alliances\n• Contested areas where spheres overlap (Eastern Europe, South China Sea)\n• Belt and Road Initiative as tool for expanding Chinese sphere\n• NATO expansion as extending Western sphere\n• Consequences: proxy conflicts, competing development models' },
      { q: 'Explain how international organisations attempt to resolve border disputes. Assess their effectiveness.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation with assessment of effectiveness. Multiple examples.\nLevel 2 (4-6 marks): Some explanation with partial assessment.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nMechanisms:\n• International Court of Justice (ICJ): rules on territorial disputes\n• UN mediation and peacekeeping\n• Regional organisations: AU, ASEAN mediation\n• Bilateral negotiation supported by international community\n• UNCLOS for maritime boundaries\nEffective examples:\n• ICJ ruling on Nigeria-Cameroon border (Bakassi Peninsula)\n• Eritrea-Ethiopia boundary commission\n• Maritime boundary agreements\nIneffective examples:\n• Israel-Palestine: decades of failed negotiations\n• Kashmir: UN resolutions unimplemented\n• South China Sea: China ignores ICJ ruling\nAssessment:\n• More effective when both parties willing to engage\n• Powerful states can ignore rulings\n• Legal processes are slow\n• Some disputes are fundamentally about power, not law' },
      { q: 'Explain how migration and demographic change can challenge the concept of the nation-state.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple challenges with clear reasoning.\nLevel 2 (4-6 marks): Some challenges identified with partial explanation.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Nation-state concept assumes population shares common national identity\n• Migration creates multicultural, multi-ethnic populations\n• Challenges to homogeneous national identity narratives\n• Dual citizenship and transnational identities blur national belonging\n• Diaspora communities maintain connections to multiple nations\n• Political tension: who belongs and who is included in the nation?\n• Rise of populist nationalism as reaction to demographic change\n• Questions of citizenship, integration, and multiculturalism\n• Stateless populations (Rohingya, Palestinians) challenge state-based system\n• Refugee flows crossing borders in large numbers\n• Examples: Europe\'s migration debates, identity politics in many countries' },
      { q: 'Explain how environmental challenges create new geopolitical issues related to power and borders.', marks: 8, markScheme: 'Level 3 (7-8 marks): Detailed explanation of multiple environmental geopolitical issues. Well-evidenced.\nLevel 2 (4-6 marks): Some issues discussed with partial evidence.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\n• Climate change: global problem requiring cooperation beyond borders\n• But disagreement over who bears responsibility and costs\n• Water resources: transboundary rivers create geopolitical tensions\n• Arctic: melting ice opens new shipping routes and resource access, disputed by multiple nations\n• Rising sea levels: small island states losing territory, implications for borders and sovereignty\n• Climate migration creating cross-border population movements\n• Environmental refugees not recognised in international law\n• Resource scarcity (water, arable land) as driver of conflict\n• Renewable energy transition changing resource geopolitics (away from oil states)\n• Examples: Arctic Council disputes, Nile dam conflict, Pacific island nations' },
      { q: 'Assess the view that power in the 21st century is increasingly exercised through economics rather than military force.', marks: 9, markScheme: 'Level 3 (7-9 marks): Thorough assessment with balanced evidence. Clear judgement.\nLevel 2 (4-6 marks): Some assessment with partial evidence.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nEconomic power increasing:\n• Trade agreements and sanctions as tools of influence\n• China\'s Belt and Road Initiative: economic leverage\n• TNCs with revenues exceeding nations\' GDP\n• Currency power: US dollar dominance\n• Control of technology and data\n• Economic interdependence makes military action costly\nMilitary power still important:\n• Russia\'s invasion of Ukraine\n• US military spending exceeds next ten countries combined\n• Nuclear deterrence remains central to great power relations\n• Ongoing conflicts: Middle East, Africa, Asia\n• Cyber warfare as new military domain\n• Arms trade and military alliances\nAssessment:\n• Both types of power remain important\n• Context determines which is more relevant\n• Smart power: effective states combine both\n• New forms of power: information, technology' },

      // 12-20 mark questions (5)
      { q: '"State sovereignty is an outdated concept in an increasingly interconnected world." To what extent do you agree?', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation with well-developed arguments from multiple perspectives. Clear, justified judgement.\nLevel 3 (9-12 marks): Good discussion with some balance.\nLevel 2 (5-8 marks): Some relevant points with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nOutdated:\n• Global challenges (climate change, pandemics) require collective action\n• Economic globalisation limits independent policy-making\n• International law and human rights norms override sovereignty\n• TNCs and international organisations exercise power across borders\n• Cyberspace and information flow ignore borders\n• Pooled sovereignty in organisations like EU\nStill relevant:\n• States remain primary actors in international relations\n• Pandemic showed states reasserting border controls\n• Rising nationalism and protectionism\n• Military power still controlled by states\n• Citizens identify primarily with nation-states\n• International organisations rely on state consent\nEvaluation:\n• Sovereignty is changing rather than disappearing\n• Different aspects of sovereignty challenged to different degrees\n• Power and wealth determine how much sovereignty a state can exercise\n• Not a binary: sovereignty exists on a spectrum' },
      { q: 'Evaluate the extent to which the global governance system needs reform to address 21st century challenges.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation of reform needs across multiple institutions. Clear, evidenced judgement.\nLevel 3 (9-12 marks): Good discussion of reform with some examples.\nLevel 2 (5-8 marks): Some points with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nReform needed:\n• UN Security Council: P5 composition outdated, veto power problematic\n• WTO: Doha round failure, need to address digital trade, climate\n• International financial institutions: voting rights don\'t reflect current economic reality\n• No governance framework for cyberspace, AI, space\n• Climate governance inadequate given scale of crisis\n• Representation of developing world insufficient\nReform difficult because:\n• Powerful states resist losing privilege\n• Consensus-based decision-making is slow\n• National interests override global interests\n• Alternative models (Chinese, Russian) compete with liberal order\nExamples:\n• G20 as informal alternative to formal institutions\n• Paris Agreement as flexible approach vs binding rules\n• Failed UN reform proposals\n• Assessment of whether incremental or fundamental change is needed' },
      { q: 'Discuss the extent to which borders remain significant in a globalised world. Use examples.', marks: 20, markScheme: 'Level 5 (17-20 marks): Exceptional discussion with sophisticated understanding of borders\' changing significance. Sustained, nuanced argument.\nLevel 4 (13-16 marks): Detailed discussion with good range of examples.\nLevel 3 (9-12 marks): Some discussion with partial development.\nLevel 2 (5-8 marks): Limited discussion.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nBorders less significant:\n• Free trade areas reduce economic borders\n• Digital communication and information flow ignore borders\n• Global supply chains cross borders continuously\n• EU freedom of movement (Schengen area)\n• Cultural globalisation transcends national boundaries\n• Environmental issues cross borders\n• TNCs operate as if borders don\'t exist\nBorders still significant:\n• Immigration controls remain powerful\n• Brexit: UK chose to re-establish borders with EU\n• Border walls: US-Mexico, Israel-Palestine\n• COVID-19: rapid border closures worldwide\n• Territorial disputes: borders matter for sovereignty\n• Different legal systems, regulations, taxes at borders\n• Cultural and linguistic differences persist at borders\nDiscussion:\n• Significance varies by type of border and what is crossing it\n• Borders are more open for goods and capital than for people\n• Power determines border permeability\n• Borders are socially constructed and their meaning changes\n• New types of borders emerging: digital, economic\n• Named examples from different regions and contexts' },
      { q: 'Assess the challenges of maintaining international peace and security in a multi-polar world.', marks: 12, markScheme: 'Level 4 (10-12 marks): Thorough assessment of challenges with clear understanding of multi-polarity. Well-evidenced.\nLevel 3 (7-9 marks): Good range of challenges discussed.\nLevel 2 (4-6 marks): Some challenges identified with limited assessment.\nLevel 1 (1-3 marks): Basic description.\n\nIndicative content:\nChallenges:\n• No single power to enforce international norms\n• Multiple competing interests make consensus difficult\n• Regional rivalries and proxy conflicts\n• Arms races and military competition\n• Nuclear proliferation risks\n• Difficulty coordinating responses to crises\n• Rising nationalism reduces cooperation\n• New domains of conflict: cyber, space, information\n• Climate change as a threat multiplier\nCounterpoints:\n• Multi-polarity can create balance of power\n• Multiple centres of power may prevent any one from dominating\n• Regional organisations can manage local conflicts\n• Economic interdependence raises cost of conflict\nExamples:\n• US-China rivalry\n• Russia-NATO tensions\n• Middle East power dynamics\n• Assessment of whether multi-polarity makes war more or less likely' },
      { q: '"Soft power is more effective than hard power in achieving a country\'s foreign policy goals." Evaluate this statement with reference to examples.', marks: 16, markScheme: 'Level 4 (13-16 marks): Thorough evaluation with well-developed examples of both power types. Clear, justified judgement.\nLevel 3 (9-12 marks): Good evaluation with some balance and examples.\nLevel 2 (5-8 marks): Some relevant points with limited evaluation.\nLevel 1 (1-4 marks): Basic description.\n\nIndicative content:\nSoft power effective:\n• Builds lasting influence without creating resentment\n• Cultural attraction creates willing cooperation\n• Less costly than military intervention\n• Examples: US cultural influence, Japan\'s technological reputation\n• EU as a model of soft power projection\n• Effective for building alliances and partnerships\nHard power effective:\n• Sometimes necessary when diplomacy fails\n• Deterrence prevents aggression (nuclear weapons)\n• Quick results in some situations\n• Soft power alone cannot stop determined aggressors\n• Examples: NATO deterrence, US military alliances\nLimitations of each:\n• Soft power is slow and difficult to measure\n• Hard power can backfire (Iraq War)\n• Both have costs and unintended consequences\nEvaluation:\n• Smart power: most effective states combine both\n• Context determines which is more appropriate\n• Different goals require different tools\n• Relative effectiveness varies by situation\n• Trend towards soft/smart power but hard power remains essential' },
    ],
  },
};

if (typeof module !== 'undefined') module.exports = { GEOGRAPHY_OCR_PRACTICE };
